{
  "name": "HydrateMe",
  "description": "A personalized hydration tracker that calculates optimal water intake based on your body metrics and provides AI-powered wellness advice.",
  "requestFramePermissions": [
    "notifications"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Gender {
  MALE = 'Male',
  FEMALE = 'Female',
  OTHER = 'Other'
}

export enum ActivityLevel {
  SEDENTARY = 'Sedentary',
  LIGHT = 'Light',
  MODERATE = 'Moderate',
  ACTIVE = 'Very Active'
}

export interface UserProfile {
  name: string;
  weight: number; // in kg
  height: number; // in cm
  gender: Gender;
  age: number;
  activityLevel: ActivityLevel;
  dailyGoal: number; // in ml
}

export interface IntakeLog {
  id: string;
  amount: number; // in ml
  timestamp: number;
  type: string; // e.g., "Water", "Tea", "Coffee"
}

export interface DailySummary {
  date: string; // YYYY-MM-DD
  total: number;
  goal: number;
}

import React from 'react';
import { Droplet, Coffee, Beer, Soup, GlassWater } from 'lucide-react';

export const INTAKE_PRESETS = [
  { label: 'Small Glass', amount: 200, icon: <GlassWater className="w-5 h-5" /> },
  { label: 'Medium Glass', amount: 350, icon: <GlassWater className="w-6 h-6" /> },
  { label: 'Large Bottle', amount: 500, icon: <Droplet className="w-6 h-6" /> },
  { label: 'Large Bottle XL', amount: 750, icon: <Droplet className="w-7 h-7" /> },
];

export const OTHER_DRINKS = [
  { label: 'Coffee', amount: 250, icon: <Coffee className="w-5 h-5" />, hydratingFactor: 0.9 },
  { label: 'Tea', amount: 250, icon: <Soup className="w-5 h-5" />, hydratingFactor: 0.95 },
  { label: 'Juice', amount: 300, icon: <Beer className="w-5 h-5" />, hydratingFactor: 0.85 },
];

export const STORAGE_KEYS = {
  USER_PROFILE: 'hydrate_me_user_profile',
  INTAKE_LOGS: 'hydrate_me_intake_logs',
};

import { UserProfile, Gender, ActivityLevel } from '../types';

export const calculateHydrationGoal = (
  weight: number,
  height: number,
  gender: Gender,
  activityLevel: ActivityLevel
): number => {
  // Basic calculation: 35ml per kg of body weight
  let goal = weight * 35;

  // Height adjustment (small factor)
  if (height > 180) goal += 200;

  // Gender adjustment
  if (gender === Gender.MALE) goal += 300;

  // Activity level adjustment
  switch (activityLevel) {
    case ActivityLevel.LIGHT: goal += 300; break;
    case ActivityLevel.MODERATE: goal += 600; break;
    case ActivityLevel.ACTIVE: goal += 1000; break;
  }

  return Math.round(goal);
};

export const getTodayKey = (): string => {
  return new Date().toISOString().split('T')[0];
};

export const formatVolume = (ml: number): string => {
  if (ml >= 1000) {
    return `${(ml / 1000).toFixed(1)}L`;
  }
  return `${ml}ml`;
};

import { GoogleGenAI } from "@google/genai";
import { UserProfile } from "../types";

export const getHydrationAdvice = async (profile: UserProfile, currentIntake: number) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `
    As a professional health and hydration coach, provide a brief, personalized tip for the user.

    User Profile:
    - Age: ${profile.age}
    - Gender: ${profile.gender}
    - Weight: ${profile.weight}kg
    - Height: ${profile.height}cm
    - Activity Level: ${profile.activityLevel}
    - Daily Hydration Goal: ${profile.dailyGoal}ml
    - Current Intake Today: ${currentIntake}ml

    Current Progress: ${Math.round((currentIntake / profile.dailyGoal) * 100)}%

    Provide a concise (max 2 sentences) encouraging tip or health fact relevant to their current status. 
    Focus on the benefits of water for their specific activity level or body metrics.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Keep drinking water to stay energized throughout your day!";
  }
};

import React, { useState } from 'react';
import { UserProfile, Gender, ActivityLevel } from '../types';
import { calculateHydrationGoal } from '../utils/calculations';
import { User, Activity, Ruler, Weight } from 'lucide-react';

interface SetupFormProps {
  onComplete: (profile: UserProfile) => void;
  initialProfile?: UserProfile | null;
}

const SetupForm: React.FC<SetupFormProps> = ({ onComplete, initialProfile }) => {
  const [formData, setFormData] = useState({
    name: initialProfile?.name || '',
    age: initialProfile?.age || 25,
    weight: initialProfile?.weight || 70,
    height: initialProfile?.height || 170,
