export default SetupForm;

import React from 'react';

interface WaterWaveProps {
  percentage: number;
}

const WaterWave: React.FC<WaterWaveProps> = ({ percentage }) => {
  const clampedPercentage = Math.min(100, Math.max(0, percentage));
  const fillLevel = 100 - clampedPercentage;

  return (
    <div className="relative w-64 h-64 rounded-full border-8 border-white shadow-2xl overflow-hidden bg-slate-50 group">
      {/* Background container for the wave */}
      <div 
        className="absolute inset-0 transition-transform duration-1000 ease-in-out"
        style={{ transform: `translateY(${fillLevel}%)` }}
      >
        <div className="relative w-[400%] h-full">
          {/* Main Wave Layer 1 */}
          <div className="absolute top-0 left-0 w-full h-24 -mt-12 bg-blue-500/40 wave-animation opacity-70">
            <svg viewBox="0 0 1000 100" preserveAspectRatio="none" className="w-full h-full fill-current">
              <path d="M0,50 C150,0 350,100 500,50 C650,0 850,100 1000,50 L1000,100 L0,100 Z" />
            </svg>
          </div>
          {/* Wave Layer 2 */}
          <div className="absolute top-0 left-0 w-full h-24 -mt-12 bg-blue-600 wave-animation opacity-90" style={{ animationDelay: '-5s' }}>
            <svg viewBox="0 0 1000 100" preserveAspectRatio="none" className="w-full h-full fill-current">
              <path d="M0,50 C150,100 350,0 500,50 C650,100 850,0 1000,50 L1000,100 L0,100 Z" />
            </svg>
          </div>
        </div>
        {/* Solid fill below waves */}
        <div className="w-full h-full bg-blue-600" />
      </div>

      {/* Percentage Display */}
      <div className="absolute inset-0 flex flex-col items-center justify-center z-10 drop-shadow-md">
        <span className={`text-5xl font-black ${percentage > 50 ? 'text-white' : 'text-blue-600'}`}>
          {Math.round(percentage)}%
        </span>
        <span className={`text-sm font-medium uppercase tracking-wider ${percentage > 50 ? 'text-blue-100' : 'text-slate-400'}`}>
          Reached
        </span>
      </div>
    </div>
  );
};

export default WaterWave;

import React from 'react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell, ReferenceLine } from 'recharts';
import { DailySummary } from '../types';

interface HistoryChartProps {
  data: DailySummary[];
}

const HistoryChart: React.FC<HistoryChartProps> = ({ data }) => {
  const processedData = data.map(item => ({
    ...item,
    displayDate: new Date(item.date).toLocaleDateString(undefined, { weekday: 'short' }),
    totalLitres: (item.total / 1000).toFixed(1),
  }));

  return (
    <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 h-80">
      <div className="flex items-center justify-between mb-6">
        <h3 className="text-lg font-bold text-slate-800">Hydration Trends</h3>
        <span className="text-xs font-medium text-slate-400 uppercase tracking-widest">Last 7 Days</span>
      </div>

      <ResponsiveContainer width="100%" height="100%">
        <BarChart data={processedData}>
          <XAxis 
            dataKey="displayDate" 
            axisLine={false} 
            tickLine={false} 
            tick={{ fill: '#94a3b8', fontSize: 12 }} 
          />
          <YAxis hide />
          <Tooltip 
            cursor={{ fill: 'transparent' }}
            content={({ active, payload }) => {
              if (active && payload && payload.length) {
                const item = payload[0].payload;
                return (
                  <div className="bg-slate-800 text-white p-2 rounded-lg text-xs shadow-xl">
                    <p className="font-bold">{item.displayDate}</p>
                    <p>{item.total}ml / {item.goal}ml</p>
                  </div>
                );
              }
              return null;
            }}
          />
          <Bar dataKey="total" radius={[8, 8, 0, 0]}>
            {processedData.map((entry, index) => (
              <Cell 
                key={`cell-${index}`} 
                fill={entry.total >= entry.goal ? '#2563eb' : '#93c5fd'} 
              />
            ))}
          </Bar>
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
};

export default HistoryChart;

import React, { useEffect, useState } from 'react';
import { Sparkles, RefreshCw } from 'lucide-react';
import { UserProfile } from '../types';
import { getHydrationAdvice } from '../services/geminiService';

interface AICoachCardProps {
  profile: UserProfile;
  currentIntake: number;
}

const AICoachCard: React.FC<AICoachCardProps> = ({ profile, currentIntake }) => {
  const [advice, setAdvice] = useState<string>('');
  const [loading, setLoading] = useState<boolean>(true);

  const fetchAdvice = async () => {
    setLoading(true);
    const text = await getHydrationAdvice(profile, currentIntake);
    setAdvice(text || "Drink up! You're doing great.");
    setLoading(false);
  };

  useEffect(() => {
    fetchAdvice();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <div className="bg-gradient-to-br from-indigo-600 to-blue-700 rounded-3xl p-6 text-white shadow-lg shadow-indigo-100 relative overflow-hidden">
      <div className="absolute top-0 right-0 -m-4 opacity-10">
        <Sparkles className="w-32 h-32 rotate-12" />
      </div>

      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <Sparkles className="w-5 h-5 text-indigo-200" />
          <h3 className="font-bold text-indigo-50">AI Health Coach</h3>
        </div>
        <button 
          onClick={fetchAdvice}
          disabled={loading}
          className="p-2 hover:bg-white/10 rounded-full transition-colors disabled:opacity-50"
        >
          <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
        </button>
      </div>

      <div className="relative z-10">
        {loading ? (
          <div className="space-y-2 animate-pulse">
            <div className="h-4 bg-white/20 rounded w-3/4" />
            <div className="h-4 bg-white/20 rounded w-1/2" />
          </div>
        ) : (
          <p className="text-lg font-medium leading-relaxed">
            "{advice}"
          </p>
        )}
      </div>
    </div>
  );
};

export default AICoachCard;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Plus, 
  Settings, 
  LogOut, 
  Trash2, 
  Clock, 
  History, 
  ChevronRight,
  TrendingUp,
  Droplets
} from 'lucide-react';
import { UserProfile, IntakeLog, DailySummary } from './types';
import { STORAGE_KEYS, INTAKE_PRESETS, OTHER_DRINKS } from './constants';
import { getTodayKey, formatVolume } from './utils/calculations';
import SetupForm from './components/SetupForm';
import WaterWave from './components/WaterWave';
import AICoachCard from './components/AICoachCard';
import HistoryChart from './components/HistoryChart';

const App: React.FC = () => {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [logs, setLogs] = useState<IntakeLog[]>([]);
  const [isSettingUp, setIsSettingUp] = useState(false);
  const [activeTab, setActiveTab] = useState<'today' | 'trends'>('today');

  // Load data on mount
  useEffect(() => {
    const savedProfile = localStorage.getItem(STORAGE_KEYS.USER_PROFILE);
    const savedLogs = localStorage.getItem(STORAGE_KEYS.INTAKE_LOGS);

    if (savedProfile) {
      setProfile(JSON.parse(savedProfile));
    } else {
      setIsSettingUp(true);
    }

    if (savedLogs) {
      setLogs(JSON.parse(savedLogs));
    }
  }, []);

  // Save logs whenever they change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.INTAKE_LOGS, JSON.stringify(logs));
  }, [logs]);

  const handleProfileComplete = (newProfile: UserProfile) => {
    setProfile(newProfile);
    localStorage.setItem(STORAGE_KEYS.USER_PROFILE, JSON.stringify(newProfile));
    setIsSettingUp(false);
  };

  const addLog = (amount: number, type: string = "Water") => {
    const newLog: IntakeLog = {
      id: Math.random().toString(36).substr(2, 9),
      amount,
      type,
      timestamp: Date.now(),
    };
    setLogs(prev => [newLog, ...prev]);
  };

  const deleteLog = (id: string) => {
    setLogs(prev => prev.filter(log => log.id !== id));
  };

  const todayKey = getTodayKey();
  const todayLogs = useMemo(() => {
    return logs.filter(log => {
      const d = new Date(log.timestamp);
      return d.toISOString().split('T')[0] === todayKey;
    });
  }, [logs, todayKey]);

  const todayTotal = todayLogs.reduce((acc, log) => acc + log.amount, 0);
  const progressPercentage = profile ? (todayTotal / profile.dailyGoal) * 100 : 0;

  const historyData = useMemo<DailySummary[]>(() => {
    if (!profile) return [];

    const map = new Map<string, number>();
    const last7Days = Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - i);
      return d.toISOString().split('T')[0];
    }).reverse();

    last7Days.forEach(date => map.set(date, 0));

    logs.forEach(log => {
      const dateKey = new Date(log.timestamp).toISOString().split('T')[0];
      if (map.has(dateKey)) {
        map.set(dateKey, map.get(dateKey)! + log.amount);
      }
    });

    return Array.from(map.entries()).map(([date, total]) => ({
      date,
      total,
      goal: profile.dailyGoal
    }));
  }, [logs, profile]);

  if (isSettingUp || !profile) {
    return (
      <div className="min-h-screen bg-slate-50 py-12 px-4 flex items-center justify-center">
        <SetupForm onComplete={handleProfileComplete} initialProfile={profile} />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 px-6 py-4">
        <div className="max-w-xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-blue-600 p-2 rounded-xl">
              <Droplets className="w-6 h-6 text-white" />
            </div>
            <div>
              <h1 className="text-xl font-bold text-slate-800">HydrateMe</h1>
              <p className="text-xs text-slate-400 font-medium">Hello, {profile.name}!</p>
            </div>
          </div>
          <button 
            onClick={() => setIsSettingUp(true)}
            className="p-2 hover:bg-slate-100 rounded-full transition-colors"
          >
            <Settings className="w-6 h-6 text-slate-500" />
          </button>
        </div>
      </header>

      <main className="max-w-xl mx-auto px-6 py-8 space-y-8">
        {activeTab === 'today' ? (
          <>
            {/* Main Circle Display */}
            <div className="flex flex-col items-center justify-center space-y-6">
              <WaterWave percentage={progressPercentage} />
              <div className="text-center">
                <div className="text-4xl font-black text-slate-800">
                  {formatVolume(todayTotal)}
                </div>
                <div className="text-slate-400 font-medium">
                  of {formatVolume(profile.dailyGoal)} goal
                </div>
              </div>
            </div>

            {/* AI Coach Card */}
            <AICoachCard profile={profile} currentIntake={todayTotal} />

            {/* Quick Logging */}
            <section className="space-y-4">
              <h3 className="text-lg font-bold text-slate-800 px-1">Log Water</h3>
              <div className="grid grid-cols-2 gap-3">
                {INTAKE_PRESETS.map((preset, idx) => (
                  <button
                    key={idx}
                    onClick={() => addLog(preset.amount)}
                    className="flex items-center justify-between p-4 bg-white border border-slate-100 rounded-2xl hover:border-blue-300 hover:shadow-md transition-all active:scale-95 group"
                  >
                    <div className="flex items-center gap-3">
                      <div className="bg-blue-50 text-blue-600 p-2 rounded-lg group-hover:bg-blue-600 group-hover:text-white transition-colors">
                        {preset.icon}
                      </div>
                      <span className="font-semibold text-slate-700">{preset.amount}ml</span>
                    </div>
                    <Plus className="w-5 h-5 text-slate-300 group-hover:text-blue-500" />
                  </button>
                ))}
              </div>

              <div className="bg-white border border-slate-100 rounded-3xl p-6 shadow-sm">
                <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-4">Other Beverages</h4>
                <div className="flex gap-4 overflow-x-auto pb-2 scrollbar-hide">
                  {OTHER_DRINKS.map((drink, idx) => (
                    <button
                      key={idx}
                      onClick={() => addLog(Math.round(drink.amount * drink.hydratingFactor), drink.label)}
                      className="flex-shrink-0 flex flex-col items-center gap-2 group"
                    >
                      <div className="w-14 h-14 rounded-2xl bg-slate-50 flex items-center justify-center text-slate-600 group-hover:bg-blue-50 group-hover:text-blue-600 transition-all border border-transparent group-hover:border-blue-100">
                        {drink.icon}
                      </div>
                      <span className="text-xs font-bold text-slate-600">{drink.label}</span>
                    </button>
                  ))}
                </div>
              </div>
            </section>

            {/* Recent Logs List */}
            <section className="space-y-4 pb-8">
              <div className="flex items-center justify-between px-1">
                <h3 className="text-lg font-bold text-slate-800">Today's History</h3>
                <span className="text-sm font-medium text-blue-600">{todayLogs.length} entries</span>
              </div>
              <div className="space-y-3">
                {todayLogs.length === 0 ? (
                  <div className="text-center py-10 bg-slate-50 rounded-3xl border-2 border-dashed border-slate-200">
                    <Droplets className="w-8 h-8 text-slate-300 mx-auto mb-2" />
                    <p className="text-slate-400 text-sm font-medium">No water logged yet today.</p>
                  </div>
                ) : (
                  todayLogs.map(log => (
                    <div key={log.id} className="bg-white p-4 rounded-2xl flex items-center justify-between shadow-sm border border-slate-50 hover:shadow-md transition-shadow">
                      <div className="flex items-center gap-4">
