      {/* Percentage Display */}
      <div className="absolute inset-0 flex flex-col items-center justify-center z-10">
        <div className="relative group-hover:scale-110 transition-transform duration-300">
          <span className={`text-6xl font-black transition-all duration-500 ${clampedPercentage > 52 ? 'text-white' : 'text-blue-600'} ${isFull ? 'drop-shadow-[0_0_15px_rgba(255,255,255,0.8)]' : ''}`}>
            {Math.round(clampedPercentage)}%
          </span>
        </div>
        <span className={`text-xs font-bold uppercase tracking-[0.2em] mt-2 transition-colors duration-500 ${clampedPercentage > 52 ? 'text-blue-100' : 'text-slate-400'}`}>
          {isFull ? 'Hydrated' : 'Current'}
        </span>
      </div>

      {/* Shine effect when full */}
      {isFull && (
        <div className="absolute inset-0 bg-gradient-to-tr from-white/0 via-white/20 to-white/0 pointer-events-none animate-[pulse_3s_infinite]" />
      )}
    </div>
  );
};

