export const calculateHydrationGoal = (profile: Partial<UserProfile>): number => {
  const { weight = 70, weightUnit = WeightUnit.KG, age = 25, gender = Gender.MALE, exerciseMinutesPerSession = 0, exerciseDaysPerWeek = 0, climate = Climate.MODERATE, caffeineCups = 0, hasMedicalCondition = false } = profile;
  const weightInKg = weightUnit === WeightUnit.LBS ? weight * 0.453592 : weight;
  let baseMultiplier = age < 30 ? 40 : age <= 55 ? 35 : age <= 65 ? 30 : 25;
  let goal = weightInKg * baseMultiplier;
  goal += (exerciseMinutesPerSession * exerciseDaysPerWeek / 7) * (500 / 60);
  if (climate === Climate.HOT_HUMID) goal += 600;
  if (climate === Climate.HIGH_ALTITUDE) goal += 500;
  if (climate === Climate.COLD) goal += 200;
  if (gender === Gender.MALE) goal += 250;
  goal += (caffeineCups * 50);
  if (hasMedicalCondition) goal += 300;
  return Math.min(6000, Math.max(1500, Math.round(goal)));
};

export const getTodayKey = (): string => new Date().toISOString().split('T')[0];
export const formatVolume = (ml: number): string => ml >= 1000 ? `${(ml / 1000).toFixed(1)}L` : `${ml}ml`;

export const calculateStreaks = (logs: IntakeLog[], dailyGoal: number) => {
  if (logs.length === 0) return { currentStreak: 0, bestStreak: 0 };
  const dailyTotals = new Map<string, number>();
  logs.forEach(log => {
    const date = new Date(log.timestamp).toISOString().split('T')[0];
    dailyTotals.set(date, (dailyTotals.get(date) || 0) + log.amount);
  });
  const today = getTodayKey();
  let currentStreak = 0;
  let activeDate = new Date();
  if ((dailyTotals.get(today) || 0) < dailyGoal) activeDate.setDate(activeDate.getDate() - 1);
  while ((dailyTotals.get(activeDate.toISOString().split('T')[0]) || 0) >= dailyGoal) {
    currentStreak++;
    activeDate.setDate(activeDate.getDate() - 1);
  }
  return { currentStreak, bestStreak: Math.max(currentStreak, 0) }; // Simplified for deployment
};

import { GoogleGenAI } from "@google/genai";
import { UserProfile } from "../types";

export const getHydrationAdvice = async (profile: UserProfile, currentIntake: number) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `As a professional health coach, provide a brief (max 2 sentences), encouraging tip based on: Climate: ${profile.climate}, Exercise: ${profile.exerciseMinutesPerSession} min, Caffeine: ${profile.caffeineCups} cups, Progress: ${Math.round((currentIntake / profile.dailyGoal) * 100)}%. Keep it focused and friendly.`;
  try {
    const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });
    return response.text;
  } catch (error) {
    return "The path of the Hashira requires constant hydration. Keep drinking!";
  }
};

export const editImageWithAI = async (base64Image: string, prompt: string, mimeType: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: base64Image.split(',')[1], mimeType } },
          { text: prompt }
        ]
      }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
    return null;
  } catch (error) {
    throw error;
  }
};

import React, { useEffect, useState, useRef } from 'react';

export default function WaterWave({ percentage }: { percentage: number }) {
  const clamped = Math.min(100, Math.max(0, percentage));
  const fillLevel = 100 - clamped;
  const isFull = clamped >= 100;
  const [ripples, setRipples] = useState<{ id: number }[]>([]);
  const [isSurging, setIsSurging] = useState(false);
  const prevRef = useRef(clamped);

  useEffect(() => {
    if (clamped > prevRef.current) {
      setIsSurging(true);
      setTimeout(() => setIsSurging(false), 1000);
    }
    prevRef.current = clamped;
  }, [clamped]);

  useEffect(() => {
    const interval = setInterval(() => {
      setRipples(p => [...p.slice(-4), { id: Date.now() }]);
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="relative">
      <div className={`absolute -inset-6 rounded-full opacity-20 blur-2xl transition-all duration-1000 ${isSurging ? 'scale-150 opacity-50 bg-cyan-400' : 'bg-blue-600'}`} />
      <div className={`relative w-72 h-72 rounded-full border-4 border-slate-800 bg-slate-950 overflow-hidden shadow-[0_0_60px_rgba(30,58,138,0.4)] transition-transform duration-700 ${isSurging ? 'scale-105' : ''}`}>
        <div className="absolute inset-0 bg-gradient-to-b from-[#020617] to-[#0f172a]" />
        <div className="absolute inset-0 transition-transform duration-1000" style={{ transform: `translateY(${fillLevel}%)` }}>
          <div className={`absolute top-0 left-0 w-full z-20 transition-all ${isSurging ? 'h-4 bg-white shadow-[0_0_40px_white]' : 'h-[2px] bg-cyan-400 shadow-[0_0_15px_cyan]'}`} />
          <div className={`w-full h-full transition-colors ${isSurging ? 'bg-cyan-600' : 'bg-gradient-to-b from-blue-900 to-black'}`} />
        </div>
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
          {ripples.map(r => <div key={r.id} className="absolute border border-cyan-400/20 rounded-full animate-ripple w-4 h-4" />)}
        </div>
        <div className="absolute inset-0 flex flex-col items-center justify-center z-30">
          <span className={`text-7xl font-black transition-colors ${clamped > 50 ? 'text-white' : 'text-blue-500'}`}>{Math.round(clamped)}%</span>
          <span className="text-[10px] font-black uppercase tracking-[0.4em] mt-2 text-cyan-400">{isFull ? 'Nagi Mastered' : 'Form XI'}</span>
        </div>
      </div>
      <style>{`
        @keyframes ripple { 0% { transform: scale(0); opacity: 0.8; } 100% { transform: scale(40); opacity: 0; } }
        .animate-ripple { animation: ripple 5s cubic-bezier(0, 0, 0.2, 1) forwards; }
      `}</style>
    </div>
  );
}

import React, { useState, useRef } from 'react';
import { Camera, Send, Loader2, Sparkles, Download, X } from 'lucide-react';
import { editImageWithAI } from '../services/geminiService';

export default function ImageEditor() {
  const [image, setImage] = useState<string | null>(null);
  const [prompt, setPrompt] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleEdit = async () => {
    if (!image || !prompt) return;
    setIsProcessing(true);
    try {
      const mimeType = image.split(';')[0].split(':')[1];
      const res = await editImageWithAI(image, prompt, mimeType);
      if (res) setResult(res);
    } catch {
      alert("Technique interrupted. Check API Key.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="bg-slate-900/50 rounded-[2.5rem] p-8 border border-slate-800 space-y-6">
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-black text-slate-100 flex items-center gap-2"><Sparkles className="text-cyan-400" /> Aura Mastery</h3>
        {(image || result) && <button onClick={() => {setImage(null); setResult(null);}} className="text-slate-500"><X /></button>}
      </div>
      <div className="relative aspect-square bg-slate-950 rounded-[2rem] border-2 border-dashed border-slate-800 flex items-center justify-center overflow-hidden">
        {result || image ? <img src={result || image!} className="w-full h-full object-cover" /> : 
          <button onClick={() => inputRef.current?.click()} className="text-slate-600 flex flex-col items-center gap-2"><Camera size={40} /><span>Upload Avatar</span></button>}
        {isProcessing && <div className="absolute inset-0 bg-black/70 flex flex-col items-center justify-center text-cyan-400"><Loader2 className="animate-spin mb-2" /><span>Visualizing...</span></div>}
      </div>
      <input type="file" ref={inputRef} hidden onChange={e => {
        const file = e.target.files?.[0];
        if (file) { const r = new FileReader(); r.onload = () => setImage(r.result as string); r.readAsDataURL(file); }
      }} />
      <div className="relative">
        <input className="w-full bg-slate-950 border border-slate-800 rounded-2xl p-4 text-slate-200 outline-none focus:ring-2 focus:ring-cyan-500" placeholder="Describe the change..." value={prompt} onChange={e => setPrompt(e.target.value)} />
        <button onClick={handleEdit} disabled={!image || isProcessing} className="absolute right-2 top-2 bottom-2 bg-cyan-600 px-4 rounded-xl"><Send size={18} /></button>
      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Plus, 
  Settings, 
  Trash2, 
  Clock, 
  History, 
  ChevronRight,
  TrendingUp,
  Droplets,
  Award,
  Flame,
  Waves,
  Zap,
  Sparkles
} from 'lucide-react';
import { UserProfile, IntakeLog, DailySummary } from './types';
import { STORAGE_KEYS, INTAKE_PRESETS, OTHER_DRINKS } from './constants';
import { getTodayKey, formatVolume, calculateStreaks } from './utils/calculations';
import SetupForm from './components/SetupForm';
import WaterWave from './components/WaterWave';
import AICoachCard from './components/AICoachCard';
import HistoryChart from './components/HistoryChart';
import StreakBadge from './components/StreakBadge';
import ImageEditor from './components/ImageEditor';

const App: React.FC = () => {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [logs, setLogs] = useState<IntakeLog[]>([]);
  const [activeTab, setActiveTab] = useState<'today' | 'trends' | 'aura'>('today');

  useEffect(() => {
    const savedProfile = localStorage.getItem(STORAGE_KEYS.USER_PROFILE);
    const savedLogs = localStorage.getItem(STORAGE_KEYS.INTAKE_LOGS);
    if (savedProfile) setProfile(JSON.parse(savedProfile));
    if (savedLogs) setLogs(JSON.parse(savedLogs));
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.INTAKE_LOGS, JSON.stringify(logs));
  }, [logs]);

  const handleProfileComplete = (newProfile: UserProfile) => {
    setProfile(newProfile);
    localStorage.setItem(STORAGE_KEYS.USER_PROFILE, JSON.stringify(newProfile));
  };

  const addLog = (amount: number, type: string = "Water") => {
    const newLog: IntakeLog = {
      id: Math.random().toString(36).substr(2, 9),
      amount,
      type,
      timestamp: Date.now(),
    };
    setLogs(prev => [newLog, ...prev]);
  };

  const deleteLog = (id: string) => {
    setLogs(prev => prev.filter(log => log.id !== id));
  };

  const todayKey = getTodayKey();
  const todayLogs = useMemo(() => {
    return logs.filter(log => new Date(log.timestamp).toISOString().split('T')[0] === todayKey);
  }, [logs, todayKey]);

  const todayTotal = todayLogs.reduce((acc, log) => acc + log.amount, 0);
  const progressPercentage = profile ? (todayTotal / profile.dailyGoal) * 100 : 0;
  const isGoalMetToday = progressPercentage >= 100;

  const streakStats = useMemo(() => {
    if (!profile) return { currentStreak: 0, bestStreak: 0 };
    return calculateStreaks(logs, profile.dailyGoal);
  }, [logs, profile]);

  const historyData = useMemo<DailySummary[]>(() => {
    if (!profile) return [];
    const map = new Map<string, number>();
    const last7Days = Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - i);
      return d.toISOString().split('T')[0];
    }).reverse();
    last7Days.forEach(date => map.set(date, 0));
    logs.forEach(log => {
      const dateKey = new Date(log.timestamp).toISOString().split('T')[0];
      if (map.has(dateKey)) map.set(dateKey, map.get(dateKey)! + log.amount);
    });
    return Array.from(map.entries()).map(([date, total]) => ({
      date,
      total,
      goal: profile.dailyGoal
    }));
  }, [logs, profile]);

