          0% { transform: translateX(100%) translateY(-50%) rotate(-20deg); opacity: 0; }
          30% { opacity: 1; }
          100% { transform: translateX(-100%) translateY(50%) rotate(-20deg); opacity: 0; }
        }
        @keyframes slash-3 {
          0% { transform: translateX(-50%) translateY(-100%) rotate(60deg); opacity: 0; }
          40% { opacity: 1; }
          100% { transform: translateX(50%) translateY(100%) rotate(60deg); opacity: 0; }
        }
        @keyframes slash-flash {
          0% { opacity: 0; }
          50% { opacity: 1; }
          100% { opacity: 0; }
        }
        @keyframes form-slide {
          0% { transform: translateX(-100%) skewX(-20deg); opacity: 0; }
          20% { transform: translateX(0) skewX(0deg); opacity: 1; }
          80% { transform: translateX(0) skewX(0deg); opacity: 1; }
          100% { transform: translateX(100%) skewX(20deg); opacity: 0; }
        }
        .animate-slash-1 { animation: slash-1 0.4s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        .animate-slash-2 { animation: slash-2 0.45s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        .animate-slash-3 { animation: slash-3 0.5s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        .animate-slash-flash { animation: slash-flash 0.6s ease-out forwards; }
