);

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Plus, 
  Settings, 
  Trash2, 
  Clock, 
  History, 
  ChevronRight,
  TrendingUp,
  Droplets,
  Award,
  Flame,
  Waves,
  Zap,
  Sparkles
} from 'lucide-react';
import { UserProfile, IntakeLog, DailySummary } from './types';
import { STORAGE_KEYS, INTAKE_PRESETS, OTHER_DRINKS } from './constants';
import { getTodayKey, formatVolume, calculateStreaks } from './utils/calculations';
import SetupForm from './components/SetupForm';
import WaterWave from './components/WaterWave';
import AICoachCard from './components/AICoachCard';
import HistoryChart from './components/HistoryChart';
import StreakBadge from './components/StreakBadge';
import ImageEditor from './components/ImageEditor';
import CharacterStage from './components/CharacterStage';

const App: React.FC = () => {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [logs, setLogs] = useState<IntakeLog[]>([]);
  const [activeTab, setActiveTab] = useState<'today' | 'trends' | 'aura'>('today');
  const [showSlash, setShowSlash] = useState(false);

  useEffect(() => {
    const savedProfile = localStorage.getItem(STORAGE_KEYS.USER_PROFILE);
    const savedLogs = localStorage.getItem(STORAGE_KEYS.INTAKE_LOGS);
    if (savedProfile) setProfile(JSON.parse(savedProfile));
    if (savedLogs) setLogs(JSON.parse(savedLogs));
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.INTAKE_LOGS, JSON.stringify(logs));
  }, [logs]);

  const handleProfileComplete = (newProfile: UserProfile) => {
    setProfile(newProfile);
    localStorage.setItem(STORAGE_KEYS.USER_PROFILE, JSON.stringify(newProfile));
  };

  const addLog = (amount: number, type: string = "Water") => {
    setShowSlash(true);
    setTimeout(() => setShowSlash(false), 600);

    const newLog: IntakeLog = {
      id: Math.random().toString(36).substr(2, 9),
      amount,
      type,
      timestamp: Date.now(),
    };
    setLogs(prev => [newLog, ...prev]);
  };

  const deleteLog = (id: string) => {
    setLogs(prev => prev.filter(log => log.id !== id));
  };

  const todayKey = getTodayKey();
  const todayLogs = useMemo(() => {
    return logs.filter(log => new Date(log.timestamp).toISOString().split('T')[0] === todayKey);
  }, [logs, todayKey]);

  const todayTotal = todayLogs.reduce((acc, log) => acc + log.amount, 0);
  const progressPercentage = profile ? (todayTotal / profile.dailyGoal) * 100 : 0;
  const isGoalMetToday = progressPercentage >= 100;

  const streakStats = useMemo(() => {
    if (!profile) return { currentStreak: 0, bestStreak: 0 };
    return calculateStreaks(logs, profile.dailyGoal);
  }, [logs, profile]);

  const historyData = useMemo<DailySummary[]>(() => {
    if (!profile) return [];
    const map = new Map<string, number>();
    const last7Days = Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - i);
      return d.toISOString().split('T')[0];
    }).reverse();
    last7Days.forEach(date => map.set(date, 0));
    logs.forEach(log => {
      const dateKey = new Date(log.timestamp).toISOString().split('T')[0];
      if (map.has(dateKey)) map.set(dateKey, map.get(dateKey)! + log.amount);
    });
    return Array.from(map.entries()).map(([date, total]) => ({
      date,
      total,
      goal: profile.dailyGoal
    }));
  }, [logs, profile]);

  if (!profile) {
    return (
      <div className="min-h-screen bg-slate-950 py-12 px-4 flex items-center justify-center">
        <SetupForm onComplete={handleProfileComplete} />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#020617] pb-32 text-slate-200 overflow-x-hidden relative">
      {/* Slash Animation Layer */}
      {showSlash && (
        <div className="fixed inset-0 z-[100] pointer-events-none flex items-center justify-center overflow-hidden">
          <div className="w-[200%] h-1 bg-white shadow-[0_0_30px_#fff] rotate-45 animate-slash-line" />
          <div className="absolute inset-0 bg-cyan-400/10 animate-slash-flash" />
        </div>
      )}

      <header className="bg-[#020617]/80 backdrop-blur-md border-b border-slate-800 sticky top-0 z-50 px-6 py-4 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="bg-blue-600 p-2 rounded-xl shadow-lg shadow-blue-900/40">
            <Zap className="w-5 h-5 text-white" />
          </div>
          <h1 className="text-lg font-black tracking-tight text-slate-100 italic">HASHIRA</h1>
        </div>
        <div className="flex items-center gap-4">
          <StreakBadge count={streakStats.currentStreak} />
          <button onClick={() => setProfile(null)} className="p-2 text-slate-500 hover:text-cyan-400">
            <Settings className="w-5 h-5" />
          </button>
        </div>
      </header>

      <main className="max-w-xl mx-auto px-6 py-8 space-y-10">
        {activeTab === 'today' && (
          <>
            <div className="flex flex-col items-center justify-center py-4">
              <CharacterStage percentage={progressPercentage} />

              <div className="mt-8 flex flex-col items-center space-y-12">
                <WaterWave percentage={progressPercentage} />
                <div className="text-center">
                  <div className={`text-6xl font-black transition-all ${isGoalMetToday ? 'text-cyan-400 drop-shadow-[0_0_20px_rgba(34,211,238,0.4)]' : 'text-slate-100'}`}>
                    {formatVolume(todayTotal)}
                  </div>
                  <div className="text-slate-500 font-bold uppercase tracking-widest text-[11px] mt-2">
                    Daily Goal: {formatVolume(profile.dailyGoal)}
                  </div>
                </div>
              </div>
            </div>

            <AICoachCard profile={profile} currentIntake={todayTotal} />

            <section className="space-y-5">
              <div className="flex items-center gap-2">
                <Droplets className="w-5 h-5 text-cyan-500" />
                <h3 className="text-lg font-black tracking-tight">Replenishment</h3>
              </div>
              <div className="grid grid-cols-2 gap-4">
                {INTAKE_PRESETS.map((preset, idx) => (
                  <button key={idx} onClick={() => addLog(preset.amount)} className="flex items-center gap-4 p-5 bg-slate-900/50 border border-slate-800 rounded-3xl hover:border-cyan-500 transition-all active:scale-95 group">
                    <div className="bg-slate-800 p-3 rounded-2xl group-hover:bg-cyan-600 text-cyan-400 group-hover:text-white transition-all">
                      {preset.icon}
                    </div>
                    <span className="font-black">{preset.amount}ml</span>
                  </button>
                ))}
              </div>
              <div className="bg-slate-900/30 border border-slate-800 rounded-[2.5rem] p-6 flex gap-6 overflow-x-auto scrollbar-hide">
                {OTHER_DRINKS.map((drink, idx) => (
                  <button key={idx} onClick={() => addLog(Math.round(drink.amount * drink.hydratingFactor), drink.label)} className="flex-shrink-0 flex flex-col items-center gap-2 group">
                    <div className="w-14 h-14 rounded-2xl bg-slate-900 border border-slate-800 flex items-center justify-center group-hover:bg-blue-600 transition-all">
                      {drink.icon}
                    </div>
                    <span className="text-[10px] font-black uppercase text-slate-500">{drink.label}</span>
                  </button>
                ))}
              </div>
            </section>

            <section className="space-y-4">
              <h3 className="text-lg font-black tracking-tight">Training Log</h3>
              <div className="space-y-3">
                {todayLogs.length === 0 ? (
                  <div className="text-center py-12 bg-slate-900/20 rounded-3xl border-2 border-dashed border-slate-800 text-slate-600 font-bold uppercase tracking-widest text-xs">Awaiting First Drop</div>
                ) : (
                  todayLogs.map(log => (
                    <div key={log.id} className="bg-slate-900/50 p-4 rounded-2xl flex items-center justify-between border border-slate-800">
                      <div className="flex items-center gap-4">
                        <div className="text-cyan-500"><Droplets size={20} /></div>
                        <div>
                          <div className="font-black text-lg">+{log.amount}ml</div>
                          <div className="text-[10px] text-slate-500 uppercase font-black tracking-widest">
                            {new Date(log.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} • {log.type}
                          </div>
                        </div>
                      </div>
                      <button onClick={() => deleteLog(log.id)} className="p-2 text-slate-700 hover:text-red-400"><Trash2 size={18} /></button>
                    </div>
                  ))
                )}
              </div>
            </section>
          </>
        )}

        {activeTab === 'trends' && (
          <div className="space-y-8">
            <HistoryChart data={historyData} />
            <div className="bg-slate-900/50 rounded-[2.5rem] p-10 border border-slate-800 flex flex-col items-center text-center">
              <StreakBadge count={streakStats.currentStreak} size="lg" />
              <div className="mt-8 grid grid-cols-2 w-full gap-8 border-t border-slate-800 pt-8">
                <div>
                  <div className="text-[10px] font-black text-slate-600 uppercase mb-1">Current</div>
                  <div className="text-3xl font-black text-slate-100">{streakStats.currentStreak} <span className="text-sm font-bold text-slate-500">Days</span></div>
                </div>
                <div className="border-l border-slate-800">
                  <div className="text-[10px] font-black text-slate-600 uppercase mb-1">Weekly Mean</div>
                  <div className="text-3xl font-black text-cyan-400">
                    {Math.round(historyData.reduce((acc, curr) => acc + curr.total, 0) / 7)}<span className="text-xs font-bold text-slate-500 ml-1">ml</span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'aura' && <ImageEditor />}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 bg-[#020617]/90 backdrop-blur-xl border-t border-slate-800 px-8 py-5 z-50 flex items-center justify-around">
        <NavButton active={activeTab === 'today'} icon={<Waves />} label="Tracker" onClick={() => setActiveTab('today')} />
        <NavButton active={activeTab === 'aura'} icon={<Sparkles />} label="Artistry" onClick={() => setActiveTab('aura')} />
        <NavButton active={activeTab === 'trends'} icon={<History />} label="Analytics" onClick={() => setActiveTab('trends')} />
      </nav>

      <style>{`
        @keyframes slash-line {
          0% { transform: translateX(-100%) translateY(-100%) rotate(45deg); opacity: 0; }
          20% { opacity: 1; }
          100% { transform: translateX(100%) translateY(100%) rotate(45deg); opacity: 0; }
        }
        @keyframes slash-flash {
          0% { opacity: 0; }
          50% { opacity: 1; }
          100% { opacity: 0; }
        }
        .animate-slash-line { animation: slash-line 0.4s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        .animate-slash-flash { animation: slash-flash 0.5s ease-out forwards; }
      `}</style>
    </div>
  );
};

const NavButton = ({ active, icon, label, onClick }: any) => (
  <button onClick={onClick} className={`flex flex-col items-center gap-1 transition-all ${active ? 'text-cyan-400 scale-110' : 'text-slate-600'}`}>
    <div className={`p-2 rounded-xl ${active ? 'bg-cyan-900/20' : ''}`}>{icon}</div>
    <span className="text-[9px] font-black uppercase tracking-widest">{label}</span>
  </button>
);

export default App;

import React, { useMemo } from 'react';
import { Wind, Waves, Flame } from 'lucide-react';

interface CharacterStageProps {
  percentage: number;
}

const CharacterStage: React.FC<CharacterStageProps> = ({ percentage }) => {
  const state = useMemo(() => {
    // Starting with Tanjiro instead of Zenitsu
    if (percentage < 60) return { 
      name: 'Tanjiro', 
      title: 'Water Breathing', 
      color: 'from-emerald-500 to-teal-700', 
      shadow: 'shadow-emerald-500/50',
      icon: <Wind className="w-4 h-4" />,
      text: 'Total Concentration...',
      auraClass: 'animate-breathing'
    };
    if (percentage < 100) return { 
      name: 'Giyu', 
      title: 'Dead Calm', 
      color: 'from-blue-600 to-indigo-900', 
      shadow: 'shadow-blue-500/50',
      icon: <Waves className="w-4 h-4" />,
      text: 'Nagi...',
      auraClass: 'animate-calm'
    };
    return { 
      name: 'Rengoku', 
      title: 'Flame Breathing', 
      color: 'from-orange-500 to-red-700', 
      shadow: 'shadow-red-500/50',
      icon: <Flame className="w-4 h-4" />,
      text: 'Set your heart ablaze!',
      auraClass: 'animate-blaze'
    };
  }, [percentage]);

  return (
    <div className="relative w-full flex flex-col items-center justify-center py-6 mb-4 overflow-hidden">
      {/* Background Aura Glow */}
      <div className={`absolute w-40 h-40 rounded-full blur-[60px] opacity-30 transition-all duration-1000 bg-gradient-to-br ${state.color} ${state.auraClass}`} />

      {/* Character Info */}
      <div className="z-10 text-center space-y-1">
        <div className="flex items-center justify-center gap-2">
          <span className={`p-1 rounded-md bg-gradient-to-br ${state.color} text-white shadow-lg`}>
            {state.icon}
          </span>
          <h2 className="text-xl font-black italic tracking-tighter text-slate-100 uppercase">
            {state.name}
          </h2>
        </div>
        <p className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-500">
          {state.title}
        </p>
      </div>

      {/* Floating Silhouette Representation */}
      <div className="relative mt-4 h-12 w-full flex justify-center items-end">
        <div className={`w-8 h-1 bg-slate-800 rounded-full blur-sm opacity-50 mb-[-4px]`} />
        <div className={`absolute bottom-0 w-10 h-16 bg-gradient-to-t ${state.color} opacity-40 blur-md rounded-t-full ${state.auraClass}`} />
        <div className="z-20 text-[8px] font-bold text-slate-400 bg-slate-900/80 px-3 py-1 rounded-full border border-slate-800 animate-bounce">
          "{state.text}"
        </div>
      </div>

      <style>{`
        @keyframes breathing {
          0%, 100% { transform: scale(1); opacity: 0.3; }
          50% { transform: scale(1.4); opacity: 0.5; }
        }
        @keyframes calm {
