import React, { useState, useRef } from 'react';
import { Camera, Send, Loader2, Sparkles, Download, X, Cloud } from 'lucide-react';
import { editImageWithAI } from '../services/geminiService';

export default function ImageEditor() {
  const [image, setImage] = useState<string | null>(null);
  const [prompt, setPrompt] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleEdit = async () => {
    if (!image || !prompt) return;
    setIsProcessing(true);
    try {
      const mimeType = image.split(';')[0].split(':')[1];
      const res = await editImageWithAI(image, prompt, mimeType);
      if (res) setResult(res);
    } catch {
      alert("Sky calibration error. Ensure your Cloud Key is valid.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="bg-sky-950/20 rounded-[3rem] p-8 border border-sky-900/30 space-y-6 backdrop-blur-md">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
            <Cloud className="text-sky-400 w-6 h-6" />
            <h3 className="text-lg font-black text-white italic tracking-tighter">Cloud Persona</h3>
        </div>
        {(image || result) && (
          <button 
            onClick={() => {setImage(null); setResult(null);}} 
            className="p-2 bg-sky-900/40 rounded-xl text-sky-400 hover:bg-sky-800 transition-colors"
          >
            <X size={18} />
          </button>
        )}
      </div>

      <div className="relative aspect-square bg-sky-950 border-4 border-sky-900/30 rounded-[2.5rem] flex items-center justify-center overflow-hidden group shadow-2xl">
        {result || image ? (
          <img src={result || image!} className="w-full h-full object-cover transition-transform group-hover:scale-105 duration-1000" />
        ) : (
          <button 
            onClick={() => inputRef.current?.click()} 
            className="text-sky-800 flex flex-col items-center gap-4 hover:text-sky-400 transition-colors"
          >
            <div className="p-6 bg-sky-900/20 rounded-full border-2 border-dashed border-sky-900">
                <Camera size={48} />
            </div>
            <span className="font-black uppercase tracking-widest text-xs">Calibrate Lens</span>
          </button>
        )}

        {isProcessing && (
          <div className="absolute inset-0 bg-sky-950/80 flex flex-col items-center justify-center text-sky-300 backdrop-blur-sm">
            <Loader2 className="animate-spin mb-4 w-10 h-10" />
            <span className="font-black uppercase tracking-[0.3em] text-xs">Uploading to Sky...</span>
          </div>
        )}
      </div>

      <input 
        type="file" 
        ref={inputRef} 
        hidden 
        onChange={e => {
          const file = e.target.files?.[0];
          if (file) { 
            const r = new FileReader(); 
            r.onload = () => setImage(r.result as string); 
            r.readAsDataURL(file); 
          }
        }} 
      />

      <div className="relative group">
        <input 
          className="w-full bg-sky-950/50 border border-sky-900/50 rounded-2xl py-5 px-6 text-white outline-none focus:ring-2 focus:ring-sky-500 transition-all font-black text-sm placeholder-sky-900/40" 
          placeholder="Manifest a new horizon..." 
          value={prompt} 
          onChange={e => setPrompt(e.target.value)} 
        />
        <button 
          onClick={handleEdit} 
          disabled={!image || isProcessing} 
          className="absolute right-2 top-2 bottom-2 bg-sky-500 hover:bg-sky-400 disabled:bg-sky-900 disabled:opacity-50 text-white px-6 rounded-xl transition-all shadow-lg active:scale-95"
        >
          <Send size={20} />
        </button>
      </div>

      <p className="text-[10px] text-sky-900 font-bold uppercase text-center tracking-widest">
        AI Imagery powered by Gemini 2.5
      </p>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Settings, 
  Trash2, 
  History, 
  Droplets,
  Waves,
  Sparkles,
  Droplet,
  Sword,
  Shield,
  Zap,
  Flame,
  Wind
} from 'lucide-react';
import { UserProfile, IntakeLog, DailySummary } from './types';
import { STORAGE_KEYS, INTAKE_PRESETS, OTHER_DRINKS } from './constants';
import { getTodayKey, formatVolume, calculateStreaks } from './utils/calculations';
import SetupForm from './components/SetupForm';
import WaterWave from './components/WaterWave';
import AICoachCard from './components/AICoachCard';
import HistoryChart from './components/HistoryChart';
import StreakBadge from './components/StreakBadge';
import ImageEditor from './components/ImageEditor';
import CharacterStage from './components/CharacterStage';

const App: React.FC = () => {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [logs, setLogs] = useState<IntakeLog[]>([]);
  const [activeTab, setActiveTab] = useState<'today' | 'trends' | 'aura'>('today');

  useEffect(() => {
    const savedProfile = localStorage.getItem(STORAGE_KEYS.USER_PROFILE);
    const savedLogs = localStorage.getItem(STORAGE_KEYS.INTAKE_LOGS);
    if (savedProfile) setProfile(JSON.parse(savedProfile));
    if (savedLogs) setLogs(JSON.parse(savedLogs));
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.INTAKE_LOGS, JSON.stringify(logs));
  }, [logs]);

  const handleProfileComplete = (newProfile: UserProfile) => {
    setProfile(newProfile);
    localStorage.setItem(STORAGE_KEYS.USER_PROFILE, JSON.stringify(newProfile));
  };

  const addLog = (amount: number, type: string = "Water") => {
    const newLog: IntakeLog = {
      id: Math.random().toString(36).substr(2, 9),
      amount,
      type,
      timestamp: Date.now(),
    };
    setLogs(prev => [newLog, ...prev]);
  };

  const deleteLog = (id: string) => {
    setLogs(prev => prev.filter(log => log.id !== id));
  };

  const todayKey = getTodayKey();
  const todayLogs = useMemo(() => {
    return logs.filter(log => new Date(log.timestamp).toISOString().split('T')[0] === todayKey);
  }, [logs, todayKey]);

  const todayTotal = todayLogs.reduce((acc, log) => acc + log.amount, 0);
  const progressPercentage = profile ? (todayTotal / profile.dailyGoal) * 100 : 0;
  const isGoalMetToday = progressPercentage >= 100;

  const streakStats = useMemo(() => {
    if (!profile) return { currentStreak: 0, bestStreak: 0 };
    return calculateStreaks(logs, profile.dailyGoal);
  }, [logs, profile]);

  const historyData = useMemo<DailySummary[]>(() => {
    if (!profile) return [];
    const map = new Map<string, number>();
    const last7Days = Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - i);
      return d.toISOString().split('T')[0];
    }).reverse();
    last7Days.forEach(date => map.set(date, 0));
    logs.forEach(log => {
      const dateKey = new Date(log.timestamp).toISOString().split('T')[0];
      if (map.has(dateKey)) map.set(dateKey, map.get(dateKey)! + log.amount);
    });
    return Array.from(map.entries()).map(([date, total]) => ({
      date,
      total,
      goal: profile.dailyGoal
    }));
  }, [logs, profile]);

  if (!profile) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4">
        <SetupForm onComplete={handleProfileComplete} />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#02040a] pb-32 text-slate-100 overflow-x-hidden relative selection:bg-cyan-500/30">

      {/* Background Cinematic Layers */}
      <div className="fixed inset-0 pointer-events-none z-0 overflow-hidden">
        {/* Deep Forest Gradient */}
        <div className="absolute inset-0 bg-gradient-to-b from-[#02040a] via-[#0b1221] to-[#02040a] opacity-100" />

        {/* Distant Trees / Mist silhouettes */}
        <div className="absolute bottom-0 left-0 right-0 h-[60vh] bg-[url('https://www.transparenttextures.com/patterns/dark-matter.png')] opacity-20" />

        {/* Parallax Fog */}
        <div className="absolute inset-0 opacity-40 mix-blend-screen animate-fog-slow" 
          style={{ backgroundImage: 'radial-gradient(circle at 50% 50%, rgba(255,255,255,0.05) 0%, transparent 70%)' }} />

        {/* Glowing Embers/Particles */}
        <div className="absolute inset-0 z-10">
          {[...Array(20)].map((_, i) => (
            <div key={i} className="absolute bg-white/40 rounded-full blur-[1px] animate-float-particle" 
              style={{
                width: Math.random() * 4 + 2 + 'px',
                height: Math.random() * 4 + 2 + 'px',
                left: Math.random() * 100 + '%',
                top: Math.random() * 100 + '%',
                animationDelay: Math.random() * 5 + 's',
                animationDuration: Math.random() * 10 + 10 + 's'
              }} 
            />
          ))}
        </div>

        {/* Moon Glow */}
        <div className="absolute top-[-10%] right-[-10%] w-[500px] h-[500px] bg-blue-500/10 blur-[120px] rounded-full" />
      </div>

      <header className="relative z-50 bg-black/40 backdrop-blur-xl border-b border-white/5 px-6 py-5 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="relative">
            <div className="absolute inset-0 bg-cyan-500 blur-lg opacity-40 animate-pulse" />
            <div className="relative bg-black border border-white/20 p-2.5 rounded-lg rotate-45 transform">
              <Sword className="w-5 h-5 text-cyan-400 -rotate-45" />
            </div>
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tighter text-white italic leading-none">KYOJIN</h1>
            <p className="text-[9px] font-black text-cyan-500 tracking-[0.4em] mt-1 uppercase">Hydration Slayer</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
          <StreakBadge count={streakStats.currentStreak} />
          <button onClick={() => setProfile(null)} className="p-2.5 bg-white/5 border border-white/10 rounded-xl text-slate-400 hover:text-white hover:border-cyan-500 transition-all">
            <Settings className="w-5 h-5" />
          </button>
        </div>
      </header>

      <main className="max-w-xl mx-auto px-6 py-8 space-y-12 relative z-10">
        {activeTab === 'today' && (
          <>
            <div className="flex flex-col items-center justify-center">
              <CharacterStage percentage={progressPercentage} />

              <div className="mt-4 flex flex-col items-center space-y-12 w-full">
                <WaterWave percentage={progressPercentage} />

                <div className="text-center group">
                  <div className="relative inline-block">
                    <div className="absolute -inset-4 bg-cyan-500/20 blur-2xl rounded-full opacity-0 group-hover:opacity-100 transition-opacity" />
                    <div className={`text-7xl font-black tracking-tighter italic transition-all duration-700 ${isGoalMetToday ? 'text-cyan-400 drop-shadow-[0_0_25px_rgba(34,211,238,0.6)]' : 'text-white'}`}>
                      {formatVolume(todayTotal)}
