import React, { useEffect, useState, useRef } from 'react';

export default function WaterWave({ percentage }: { percentage: number }) {
  const clamped = Math.min(100, Math.max(0, percentage));
  const fillLevel = 100 - clamped;
  const isFull = clamped >= 100;
  const [ripples, setRipples] = useState<{ id: number }[]>([]);
  const [isSurging, setIsSurging] = useState(false);
  const prevRef = useRef(clamped);

  useEffect(() => {
    if (clamped > prevRef.current) {
      setIsSurging(true);
      setTimeout(() => setIsSurging(false), 800);
    }
    prevRef.current = clamped;
  }, [clamped]);

  useEffect(() => {
    const interval = setInterval(() => {
      setRipples(p => [...p.slice(-4), { id: Date.now() }]);
    }, 2500);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="relative group">
      {/* Outer Glow Halo */}
      <div className={`absolute -inset-12 rounded-full opacity-10 blur-[100px] transition-all duration-1000 ${isSurging ? 'scale-150 opacity-40 bg-cyan-400' : 'bg-blue-600'}`} />

      {/* Main Container */}
      <div className={`relative w-72 h-72 rounded-full border-4 border-white/10 bg-black/60 overflow-hidden shadow-[0_0_100px_rgba(0,0,0,0.8)] transition-transform duration-700 ${isSurging ? 'scale-105' : ''}`}>

        {/* Background Depth */}
        <div className="absolute inset-0 bg-[#02040a]" />

        {/* Liquid Body with traditional Ukiyo-e Wave texture */}
        <div className="absolute inset-0 transition-transform duration-[1200ms] cubic-bezier(0.23, 1, 0.32, 1)" style={{ transform: `translateY(${fillLevel}%)` }}>

          {/* Glowing Surface Line (The Cutting Edge) */}
          <div className={`absolute top-0 left-0 w-full z-20 transition-all ${isSurging ? 'h-6 bg-white shadow-[0_0_50px_white]' : 'h-[3px] bg-cyan-300 shadow-[0_0_20px_#22d3ee]'}`}>
            <div className="w-full h-full bg-gradient-to-r from-transparent via-white/50 to-transparent animate-shimmer" />
          </div>

          {/* Main Liquid Area */}
          <div className={`w-full h-[200%] transition-colors relative overflow-hidden ${isSurging ? 'bg-cyan-500' : 'bg-gradient-to-b from-cyan-600 via-blue-900 to-black'}`}>
            <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/dark-matter.png')] opacity-30 mix-blend-overlay" />
            <div className="absolute top-0 left-0 right-0 h-24 bg-gradient-to-b from-white/10 to-transparent" />
          </div>
        </div>

        {/* Traditional Ripples Layer */}
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
          {ripples.map(r => (
            <div key={r.id} className="absolute border-2 border-white/10 rounded-full animate-ripple" 
              style={{ width: '10px', height: '10px' }} 
            />
          ))}
        </div>

        {/* Percentage Readout */}
        <div className="absolute inset-0 flex flex-col items-center justify-center z-30">
          <div className="relative group-hover:scale-110 transition-transform duration-500">
            <span className={`text-8xl font-black italic tracking-tighter transition-colors duration-1000 ${clamped > 50 ? 'text-white drop-shadow-[0_4px_12px_rgba(0,0,0,0.8)]' : 'text-cyan-500'}`}>
              {Math.round(clamped)}
              <span className="text-2xl ml-1 opacity-50">%</span>
            </span>
          </div>
          <div className={`text-[10px] font-black uppercase tracking-[0.6em] mt-2 transition-all duration-700 ${clamped > 50 ? 'text-cyan-100/40' : 'text-cyan-900'}`}>
            {isFull ? 'ASH BLAZE MET' : 'PULSE FLOW'}
          </div>
        </div>
      </div>

      <style>{`
        @keyframes ripple { 
          0% { transform: scale(0); opacity: 0.8; } 
          100% { transform: scale(50); opacity: 0; } 
        }
        @keyframes shimmer { 0% { transform: translateX(-100%); } 100% { transform: translateX(100%); } }
        .animate-ripple { animation: ripple 5s cubic-bezier(0, 0, 0.2, 1) forwards; }
        .animate-shimmer { animation: shimmer 3s linear infinite; }
      `}</style>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Settings, 
  Trash2, 
  History, 
  Droplets,
  Waves,
  Sparkles,
  Droplet,
  Sword,
  Shield,
  Zap,
  Flame,
  Wind
} from 'lucide-react';
import { UserProfile, IntakeLog, DailySummary } from './types';
import { STORAGE_KEYS, INTAKE_PRESETS, OTHER_DRINKS } from './constants';
import { getTodayKey, formatVolume, calculateStreaks } from './utils/calculations';
import SetupForm from './components/SetupForm';
import WaterWave from './components/WaterWave';
import AICoachCard from './components/AICoachCard';
import HistoryChart from './components/HistoryChart';
import StreakBadge from './components/StreakBadge';
import ImageEditor from './components/ImageEditor';
import CharacterStage from './components/CharacterStage';

const App: React.FC = () => {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [logs, setLogs] = useState<IntakeLog[]>([]);
  const [activeTab, setActiveTab] = useState<'today' | 'trends' | 'aura'>('today');

  useEffect(() => {
    const savedProfile = localStorage.getItem(STORAGE_KEYS.USER_PROFILE);
    const savedLogs = localStorage.getItem(STORAGE_KEYS.INTAKE_LOGS);
    if (savedProfile) setProfile(JSON.parse(savedProfile));
    if (savedLogs) setLogs(JSON.parse(savedLogs));
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.INTAKE_LOGS, JSON.stringify(logs));
  }, [logs]);

  const handleProfileComplete = (newProfile: UserProfile) => {
    setProfile(newProfile);
    localStorage.setItem(STORAGE_KEYS.USER_PROFILE, JSON.stringify(newProfile));
  };

  const addLog = (amount: number, type: string = "Water") => {
    const newLog: IntakeLog = {
      id: Math.random().toString(36).substr(2, 9),
      amount,
      type,
      timestamp: Date.now(),
    };
    setLogs(prev => [newLog, ...prev]);
  };

  const deleteLog = (id: string) => {
    setLogs(prev => prev.filter(log => log.id !== id));
  };

  const todayKey = getTodayKey();
  const todayLogs = useMemo(() => {
    return logs.filter(log => new Date(log.timestamp).toISOString().split('T')[0] === todayKey);
  }, [logs, todayKey]);

  const todayTotal = todayLogs.reduce((acc, log) => acc + log.amount, 0);
  const progressPercentage = profile ? (todayTotal / profile.dailyGoal) * 100 : 0;
  const isGoalMetToday = progressPercentage >= 100;

  const streakStats = useMemo(() => {
    if (!profile) return { currentStreak: 0, bestStreak: 0 };
    return calculateStreaks(logs, profile.dailyGoal);
  }, [logs, profile]);

  const historyData = useMemo<DailySummary[]>(() => {
    if (!profile) return [];
    const map = new Map<string, number>();
    const last7Days = Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - i);
      return d.toISOString().split('T')[0];
    }).reverse();
    last7Days.forEach(date => map.set(date, 0));
    logs.forEach(log => {
      const dateKey = new Date(log.timestamp).toISOString().split('T')[0];
      if (map.has(dateKey)) map.set(dateKey, map.get(dateKey)! + log.amount);
    });
    return Array.from(map.entries()).map(([date, total]) => ({
      date,
      total,
      goal: profile.dailyGoal
    }));
  }, [logs, profile]);

  if (!profile) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4">
        <SetupForm onComplete={handleProfileComplete} />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#02040a] pb-40 text-slate-100 overflow-x-hidden relative selection:bg-cyan-500/30">

      {/* Background Cinematic Layers */}
      <div className="fixed inset-0 pointer-events-none z-0 overflow-hidden">
        {/* Deep Forest Gradient */}
        <div className="absolute inset-0 bg-gradient-to-b from-[#02040a] via-[#0b1221] to-[#02040a] opacity-100" />

        {/* Distant Trees / Mist silhouettes */}
        <div className="absolute bottom-0 left-0 right-0 h-[60vh] bg-[url('https://www.transparenttextures.com/patterns/dark-matter.png')] opacity-20" />

        {/* Parallax Fog */}
        <div className="absolute inset-0 opacity-40 mix-blend-screen animate-fog-slow" 
          style={{ backgroundImage: 'radial-gradient(circle at 50% 50%, rgba(255,255,255,0.05) 0%, transparent 70%)' }} />

        {/* Glowing Embers/Particles */}
        <div className="absolute inset-0 z-10">
          {[...Array(20)].map((_, i) => (
            <div key={i} className="absolute bg-white/40 rounded-full blur-[1px] animate-float-particle" 
              style={{
                width: Math.random() * 4 + 2 + 'px',
                height: Math.random() * 4 + 2 + 'px',
                left: Math.random() * 100 + '%',
                top: Math.random() * 100 + '%',
                animationDelay: Math.random() * 5 + 's',
                animationDuration: Math.random() * 10 + 10 + 's'
              }} 
            />
          ))}
        </div>

        {/* Moon Glow */}
        <div className="absolute top-[-10%] right-[-10%] w-[500px] h-[500px] bg-blue-500/10 blur-[120px] rounded-full" />
