        {/* Animated Embers */}
        <div className="absolute inset-0 z-10">
          {[...Array(15)].map((_, i) => (
            <div key={i} className="absolute bg-cyan-400/40 rounded-full blur-[1px] animate-ember" 
              style={{
                width: Math.random() * 3 + 1 + 'px',
                height: Math.random() * 3 + 1 + 'px',
                left: Math.random() * 100 + '%',
                top: Math.random() * 100 + '%',
                animationDelay: Math.random() * 5 + 's',
                animationDuration: Math.random() * 7 + 5 + 's'
              }} 
            />
          ))}
        </div>
      </div>

      <header className="relative z-50 bg-black/40 backdrop-blur-xl border-b border-white/5 px-6 py-4 flex items-center justify-between shadow-2xl">
        <div className="flex items-center gap-4 group">
          <div className="relative">
            <div className="absolute inset-0 bg-cyan-500 blur-lg opacity-20 group-hover:opacity-40 transition-opacity" />
            <div className="relative bg-black border border-white/10 p-2 rounded-lg rotate-45 transform group-hover:rotate-[225deg] transition-transform duration-700">
              <Sword className="w-5 h-5 text-cyan-400 -rotate-45" />
            </div>
          </div>
          <div>
            <h1 className="text-xl font-black tracking-tighter text-white italic uppercase leading-none">Kyojin Hydrate</h1>
            <p className="text-[8px] font-black text-cyan-500 tracking-[0.4em] mt-1 uppercase opacity-60">Demon Slayer Arts</p>
          </div>
