import React, { useEffect, useState, useRef } from 'react';

export default function WaterWave({ percentage }: { percentage: number }) {
  const clamped = Math.min(100, Math.max(0, percentage));
  const fillLevel = 100 - clamped;
  const isFull = clamped >= 100;
  const [ripples, setRipples] = useState<{ id: number }[]>([]);
  const [isSurging, setIsSurging] = useState(false);
  const prevRef = useRef(clamped);

  useEffect(() => {
    if (clamped > prevRef.current) {
      setIsSurging(true);
      setTimeout(() => setIsSurging(false), 800);
    }
    prevRef.current = clamped;
  }, [clamped]);

  useEffect(() => {
    const interval = setInterval(() => {
      setRipples(p => [...p.slice(-4), { id: Date.now() }]);
    }, 2500);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="relative group">
      {/* Outer Glow */}
      <div className={`absolute -inset-10 rounded-full opacity-10 blur-[80px] transition-all duration-1000 ${isSurging ? 'scale-150 opacity-40 bg-cyan-400' : 'bg-blue-600'}`} />

      {/* Container */}
      <div className={`relative w-64 h-64 rounded-full border-[4px] border-white/10 bg-black overflow-hidden shadow-[0_0_80px_rgba(0,0,0,0.8)] transition-transform duration-700 ${isSurging ? 'scale-105' : ''}`}>

        {/* Background Depth */}
        <div className="absolute inset-0 bg-gradient-to-b from-[#02040a] to-[#0a1229]" />

        <div className="absolute inset-0 transition-transform duration-[1500ms] cubic-bezier(0.16, 1, 0.3, 1)" style={{ transform: `translateY(${fillLevel}%)` }}>
          {/* Surface Line - The Breathing Edge */}
          <div className={`absolute top-0 left-0 w-full z-20 transition-all ${isSurging ? 'h-6 bg-white shadow-[0_0_40px_white]' : 'h-[2px] bg-cyan-400 shadow-[0_0_15px_#22d3ee]'}`}>
            <div className="w-full h-full bg-gradient-to-r from-transparent via-white/50 to-transparent animate-shimmer" />
          </div>

          {/* Liquid Body */}
          <div className={`w-full h-[200%] transition-colors relative overflow-hidden ${isSurging ? 'bg-cyan-500' : 'bg-gradient-to-b from-cyan-600 via-blue-900 to-black'}`}>
            <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/dark-matter.png')] opacity-30 mix-blend-overlay" />
          </div>
        </div>

        {/* Japanese Ripples */}
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
          {ripples.map(r => <div key={r.id} className="absolute border-2 border-white/5 rounded-full animate-ripple" style={{width: '20px', height: '20px'}} />)}
        </div>

        <div className="absolute inset-0 flex flex-col items-center justify-center z-30">
          <div className="relative">
            <span className={`text-8xl font-black italic tracking-tighter transition-colors duration-1000 ${clamped > 50 ? 'text-white' : 'text-cyan-500'}`}>
              {Math.round(clamped)}
              <span className="text-xl ml-1 opacity-40">%</span>
            </span>
            <div className="absolute -inset-4 bg-white blur-3xl opacity-5 pointer-events-none" />
          </div>
          <span className={`text-[8px] font-black uppercase tracking-[0.6em] mt-2 transition-all duration-700 ${clamped > 50 ? 'text-cyan-100/40' : 'text-cyan-900'}`}>
            {isFull ? 'SLAYER ASCENT' : 'FLOW LEVEL'}
          </span>
        </div>
      </div>
      <style>{`
        @keyframes ripple { 0% { transform: scale(0); opacity: 0.8; } 100% { transform: scale(40); opacity: 0; } }
        @keyframes shimmer { 0% { transform: translateX(-100%); } 100% { transform: translateX(100%); } }
        .animate-ripple { animation: ripple 6s cubic-bezier(0, 0, 0.2, 1) forwards; }
        .animate-shimmer { animation: shimmer 3s linear infinite; }
      `}</style>
    </div>
  );
}

import React from 'react';
import { 
  ComposedChart, 
  Bar, 
  XAxis, 
  YAxis, 
  Tooltip, 
  ResponsiveContainer, 
  Cell, 
  Area, 
  ReferenceLine 
} from 'recharts';
import { DailySummary } from '../types';

interface HistoryChartProps {
  data: DailySummary[];
}

const HistoryChart: React.FC<HistoryChartProps> = ({ data }) => {
  const maxVal = Math.max(...data.map(d => Math.max(d.total, d.goal)), 1000);

  const processedData = data.map((item) => {
    const isGoalMet = item.total >= item.goal;
    return {
      ...item,
      displayDate: new Date(item.date).toLocaleDateString(undefined, { weekday: 'short' }).toUpperCase(),
      streakArea: isGoalMet ? maxVal * 1.1 : 0,
      isGoalMet,
    };
  });

  return (
    <div className="bg-black/60 rounded-[3rem] p-8 shadow-2xl border border-white/5 h-80 relative overflow-hidden backdrop-blur-xl">
      <div className="flex items-center justify-between mb-8 relative z-10">
        <div>
          <h3 className="text-xl font-black text-white italic tracking-tighter uppercase">Scroll of Flow</h3>
          <p className="text-[9px] font-black text-cyan-500 uppercase tracking-[0.3em] mt-1 opacity-60">
            Weekly Breathing Trends
          </p>
        </div>
        <div className="px-4 py-1.5 bg-white/5 rounded-full border border-white/10 text-[9px] font-black text-slate-400 uppercase tracking-widest">
          Last 7 Sun Cycles
        </div>
      </div>

      <ResponsiveContainer width="100%" height="100%">
        <ComposedChart data={processedData}>
          <defs>
            <linearGradient id="brushGradient" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#22d3ee" stopOpacity={0.1}/>
              <stop offset="95%" stopColor="#22d3ee" stopOpacity={0}/>
            </linearGradient>
          </defs>
          <XAxis 
            dataKey="displayDate" 
            axisLine={false} 
            tickLine={false} 
            tick={{ fill: '#475569', fontSize: 9, fontWeight: 900, letterSpacing: '0.2em' }} 
          />
          <YAxis hide domain={[0, maxVal * 1.1]} />
          <Tooltip 
            cursor={{ fill: 'rgba(255, 255, 255, 0.03)' }}
            content={({ active, payload }) => {
              if (active && payload && payload.length) {
                const item = payload[0].payload;
                return (
                  <div className="bg-black/90 backdrop-blur-xl text-white p-4 rounded-2xl text-[10px] shadow-2xl border border-white/10">
                    <p className="font-black mb-2 uppercase tracking-widest text-cyan-400">{item.displayDate}</p>
                    <div className="flex items-center gap-3">
                      <div className={`w-2 h-2 rounded-full ${item.isGoalMet ? 'bg-cyan-400 shadow-[0_0_10px_#22d3ee]' : 'bg-slate-800'}`} />
                      <p className="font-black">{item.total}ML <span className="text-slate-600">/ {item.goal}ML</span></p>
                    </div>
                  </div>
                );
              }
              return null;
            }}
          />

          <Area 
            type="monotone" 
            dataKey="streakArea" 
            stroke="none" 
            fill="url(#brushGradient)" 
            animationDuration={2000}
          />

          <Bar dataKey="total" radius={[4, 4, 4, 4]} barSize={24}>
            {processedData.map((entry, index) => (
              <Cell 
                key={`cell-${index}`} 
                fill={entry.total >= entry.goal ? '#22d3ee' : '#1e293b'} 
                className="transition-all duration-1000"
              />
            ))}
          </Bar>

          <ReferenceLine 
            y={data[0]?.goal || 2000} 
            stroke="rgba(255,255,255,0.05)" 
            strokeDasharray="4 4" 
          />
        </ComposedChart>
      </ResponsiveContainer>
    </div>
  );
};

