import React, { useEffect, useState, useRef } from 'react';

export default function WaterWave({ percentage }: { percentage: number }) {
  const clamped = Math.min(100, Math.max(0, percentage));
  const fillLevel = 100 - clamped;
  const isFull = clamped >= 100;
  const [ripples, setRipples] = useState<{ id: number }[]>([]);
  const [isSurging, setIsSurging] = useState(false);
  const prevRef = useRef(clamped);

  useEffect(() => {
    if (clamped > prevRef.current) {
      setIsSurging(true);
      setTimeout(() => setIsSurging(false), 800);
    }
    prevRef.current = clamped;
  }, [clamped]);

  useEffect(() => {
    const interval = setInterval(() => {
      setRipples(p => [...p.slice(-3), { id: Date.now() }]);
    }, 3000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="relative group">
      {/* Shadow Glow */}
      <div className={`absolute -inset-14 rounded-full opacity-[0.07] blur-[100px] transition-all duration-1000 ${isSurging ? 'scale-125 opacity-20 bg-blue-400' : 'bg-indigo-600'}`} />

      {/* Core Vessel */}
      <div className={`relative w-72 h-72 rounded-full border border-white/10 bg-[#080a0f] overflow-hidden shadow-[0_30px_60px_rgba(0,0,0,0.8)] transition-all duration-700 ${isSurging ? 'scale-105 border-white/20' : ''}`}>

        {/* Fill Layer */}
        <div className="absolute inset-0 transition-transform duration-[2000ms] cubic-bezier(0.16, 1, 0.3, 1)" style={{ transform: `translateY(${fillLevel}%)` }}>
          {/* Digital Surface Glow */}
          <div className={`absolute top-0 left-0 w-full z-20 transition-all ${isSurging ? 'h-8 bg-white shadow-[0_0_50px_rgba(255,255,255,0.4)]' : 'h-[2px] bg-blue-400 shadow-[0_0_20px_#3b82f6]'}`}>
            <div className="w-full h-full bg-gradient-to-r from-transparent via-white/40 to-transparent animate-scan" />
          </div>

          {/* Fluid Area */}
          <div className={`w-full h-[200%] transition-colors relative overflow-hidden ${isSurging ? 'bg-blue-500' : 'bg-gradient-to-b from-blue-600 via-indigo-950 to-black'}`}>
             <div className="absolute inset-0 opacity-[0.05] bg-[url('https://www.transparenttextures.com/patterns/pinstriped-suit.png')]" />
          </div>
        </div>

        {/* Ambient Geometry Ripples */}
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
          {ripples.map(r => (
            <div key={r.id} className="absolute border-[1px] border-white/5 rounded-full animate-ripple" 
              style={{ width: '10px', height: '10px' }} 
            />
          ))}
        </div>

        {/* Percentage Display */}
        <div className="absolute inset-0 flex flex-col items-center justify-center z-30">
          <div className="relative">
            <span className={`text-8xl font-black transition-colors duration-1000 ${clamped > 50 ? 'text-white' : 'text-blue-500'}`}>
              {Math.round(clamped)}
              <span className="text-2xl ml-1 font-bold opacity-30">%</span>
            </span>
          </div>
          <span className={`text-[9px] font-bold uppercase tracking-[0.5em] mt-3 transition-all duration-700 ${clamped > 50 ? 'text-white/40' : 'text-slate-700'}`}>
            {isFull ? 'Target Achieved' : 'Hydration Index'}
          </span>
        </div>
      </div>
      <style>{`
        @keyframes ripple { 0% { transform: scale(0); opacity: 0.6; } 100% { transform: scale(60); opacity: 0; } }
        @keyframes scan { 0% { transform: translateX(-100%); } 100% { transform: translateX(100%); } }
        .animate-ripple { animation: ripple 8s cubic-bezier(0, 0, 0.2, 1) forwards; }
        .animate-scan { animation: scan 4s linear infinite; }
      `}</style>
    </div>
  );
}

import React, { useEffect, useState } from 'react';
