import React from 'react';
import { 
  ComposedChart, 
  Bar, 
  XAxis, 
  YAxis, 
  Tooltip, 
  ResponsiveContainer, 
  Cell, 
  Area, 
  ReferenceLine 
} from 'recharts';
import { DailySummary } from '../types';

interface HistoryChartProps {
  data: DailySummary[];
}

const HistoryChart: React.FC<HistoryChartProps> = ({ data }) => {
  const maxVal = Math.max(...data.map(d => Math.max(d.total, d.goal)), 1000);

  const processedData = data.map((item) => {
    const isGoalMet = item.total >= item.goal;
    return {
      ...item,
      displayDate: new Date(item.date).toLocaleDateString(undefined, { weekday: 'short' }).toUpperCase(),
      streakArea: isGoalMet ? maxVal * 1.1 : 0,
      isGoalMet,
    };
  });

  return (
    <div className="bg-[#0a0c10] rounded-[3.5rem] p-8 md:p-10 shadow-2xl border border-white/5 h-96 relative overflow-hidden">
      <div className="flex items-center justify-between mb-10 relative z-10">
        <div>
          <h3 className="text-xl font-extrabold text-white tracking-tight">Hydration Analysis</h3>
          <p className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.3em] mt-1.5">
            Weekly Performance Metrics
          </p>
        </div>
        <div className="px-4 py-2 bg-white/[0.03] rounded-2xl border border-white/5 text-[10px] font-bold text-slate-600 uppercase tracking-widest">
          Last 7 Days
        </div>
      </div>

      <ResponsiveContainer width="100%" height="100%">
        <ComposedChart data={processedData}>
          <defs>
            <linearGradient id="areaGradient" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.08}/>
              <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
            </linearGradient>
          </defs>
          <XAxis 
            dataKey="displayDate" 
            axisLine={false} 
            tickLine={false} 
            tick={{ fill: '#475569', fontSize: 10, fontWeight: 700, letterSpacing: '0.15em' }} 
            dy={15}
          />
          <YAxis hide domain={[0, maxVal * 1.1]} />
          <Tooltip 
            cursor={{ fill: 'rgba(255, 255, 255, 0.02)' }}
            content={({ active, payload }) => {
              if (active && payload && payload.length) {
                const item = payload[0].payload;
                return (
                  <div className="bg-[#0f1218] text-white p-5 rounded-3xl text-[11px] shadow-2xl border border-white/10 backdrop-blur-xl">
                    <p className="font-extrabold mb-3 uppercase tracking-widest text-blue-400">{item.displayDate}</p>
                    <div className="flex items-center gap-3">
                      <div className={`w-2 h-2 rounded-full ${item.isGoalMet ? 'bg-blue-400 shadow-[0_0_10px_#3b82f6]' : 'bg-slate-800'}`} />
                      <p className="font-bold">{item.total}ml <span className="text-slate-600 ml-1">/ {item.goal}ml</span></p>
                    </div>
                  </div>
                );
              }
              return null;
            }}
          />

          <Area 
            type="monotone" 
            dataKey="streakArea" 
            stroke="none" 
            fill="url(#areaGradient)" 
            animationDuration={1500}
          />

          <Bar dataKey="total" radius={[8, 8, 8, 8]} barSize={28}>
            {processedData.map((entry, index) => (
              <Cell 
                key={`cell-${index}`} 
                fill={entry.total >= entry.goal ? '#3b82f6' : '#1e293b'} 
                className="transition-all duration-700"
              />
            ))}
          </Bar>

          <ReferenceLine 
            y={data[0]?.goal || 2000} 
            stroke="rgba(255,255,255,0.03)" 
            strokeDasharray="8 8" 
          />
        </ComposedChart>
      </ResponsiveContainer>
    </div>
  );
};

