import React, { useState, useRef } from 'react';
import { Camera, Send, Loader2, Sparkles, X, User } from 'lucide-react';
import { editImageWithAI } from '../services/geminiService';

export default function ImageEditor() {
  const [image, setImage] = useState<string | null>(null);
  const [prompt, setPrompt] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleEdit = async () => {
    if (!image || !prompt) return;
    setIsProcessing(true);
    try {
      const mimeType = image.split(';')[0].split(':')[1];
      const res = await editImageWithAI(image, prompt, mimeType);
      if (res) setResult(res);
    } catch {
      alert("Aura processing error. Please check your configuration.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="bg-[#0a0c10] rounded-[3.5rem] p-10 border border-white/5 space-y-8 shadow-2xl animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-4">
            <div className="p-3 bg-indigo-500/10 rounded-2xl border border-indigo-500/20 text-indigo-400">
              <User size={20} />
            </div>
            <div>
              <h3 className="text-xl font-extrabold text-white tracking-tight">Identity Portrait</h3>
              <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mt-0.5">AI-Enhanced Visualization</p>
            </div>
        </div>
        {(image || result) && (
          <button 
            onClick={() => {setImage(null); setResult(null);}} 
            className="p-2.5 bg-white/5 rounded-2xl text-slate-500 hover:text-white hover:bg-white/10 transition-all"
          >
            <X size={20} />
          </button>
        )}
      </div>

      <div className="relative aspect-square bg-[#05070a] border border-white/5 rounded-[3rem] flex items-center justify-center overflow-hidden group shadow-inner">
        {result || image ? (
          <img src={result || image!} className="w-full h-full object-cover transition-all duration-1000" />
        ) : (
          <button 
            onClick={() => inputRef.current?.click()} 
            className="text-slate-800 flex flex-col items-center gap-6 hover:text-blue-500 transition-all group"
          >
            <div className="p-8 bg-white/[0.02] rounded-full border-2 border-dashed border-white/5 group-hover:border-blue-500/30 group-hover:bg-blue-500/5 transition-all">
                <Camera size={56} className="opacity-20 group-hover:opacity-100" />
            </div>
            <span className="font-bold uppercase tracking-[0.2em] text-xs">Capture Baseline</span>
          </button>
        )}

        {isProcessing && (
          <div className="absolute inset-0 bg-[#0a0c10]/90 flex flex-col items-center justify-center text-blue-400 backdrop-blur-md">
            <div className="relative">
              <Loader2 className="animate-spin mb-6 w-12 h-12" />
              <div className="absolute inset-0 bg-blue-400 blur-2xl opacity-20 animate-pulse" />
            </div>
            <span className="font-bold uppercase tracking-[0.3em] text-[10px]">Processing Aura Neural Core...</span>
          </div>
        )}
      </div>

      <input 
        type="file" 
        ref={inputRef} 
        hidden 
        onChange={e => {
          const file = e.target.files?.[0];
          if (file) { 
            const r = new FileReader(); 
            r.onload = () => setImage(r.result as string); 
            r.readAsDataURL(file); 
          }
        }} 
      />

      <div className="relative">
        <input 
          className="w-full bg-white/[0.02] border border-white/5 rounded-3xl py-6 px-7 text-white outline-none focus:ring-1 focus:ring-blue-500 transition-all font-semibold text-sm placeholder-slate-700" 
          placeholder="Describe your visual evolution..." 
          value={prompt} 
          onChange={e => setPrompt(e.target.value)} 
        />
        <button 
          onClick={handleEdit} 
          disabled={!image || isProcessing} 
          className="absolute right-2 top-2 bottom-2 bg-blue-600 hover:bg-blue-500 disabled:bg-slate-800 disabled:opacity-50 text-white px-8 rounded-2xl transition-all shadow-xl active:scale-95 flex items-center gap-2"
        >
          <Sparkles size={18} />
          <span className="font-bold text-xs uppercase tracking-widest hidden md:inline">Enhance</span>
        </button>
      </div>

      <div className="flex items-center justify-center gap-2">
        <div className="h-[1px] w-4 bg-white/5" />
        <p className="text-[9px] text-slate-600 font-bold uppercase tracking-widest">
          Secure Neural Processing • Gemini Vision v2.5
        </p>
        <div className="h-[1px] w-4 bg-white/5" />
      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Settings, 
  Trash2, 
  History, 
  Droplets,
  Waves,
  Sparkles,
  Droplet,
  Activity,
  User,
  Layout,
  ChevronRight
} from 'lucide-react';
import { UserProfile, IntakeLog, DailySummary } from './types';
import { STORAGE_KEYS, INTAKE_PRESETS, OTHER_DRINKS } from './constants';
import { getTodayKey, formatVolume, calculateStreaks } from './utils/calculations';
import SetupForm from './components/SetupForm';
import WaterWave from './components/WaterWave';
import AICoachCard from './components/AICoachCard';
import HistoryChart from './components/HistoryChart';
import StreakBadge from './components/StreakBadge';
import ImageEditor from './components/ImageEditor';
import CharacterStage from './components/CharacterStage';

const App: React.FC = () => {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [logs, setLogs] = useState<IntakeLog[]>([]);
  const [activeTab, setActiveTab] = useState<'today' | 'trends' | 'aura'>('today');

  useEffect(() => {
    const savedProfile = localStorage.getItem(STORAGE_KEYS.USER_PROFILE);
    const savedLogs = localStorage.getItem(STORAGE_KEYS.INTAKE_LOGS);
    if (savedProfile) setProfile(JSON.parse(savedProfile));
    if (savedLogs) setLogs(JSON.parse(savedLogs));
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.INTAKE_LOGS, JSON.stringify(logs));
  }, [logs]);

  const handleProfileComplete = (newProfile: UserProfile) => {
    setProfile(newProfile);
    localStorage.setItem(STORAGE_KEYS.USER_PROFILE, JSON.stringify(newProfile));
  };

  const addLog = (amount: number, type: string = "Water") => {
    const newLog: IntakeLog = {
      id: Math.random().toString(36).substr(2, 9),
      amount,
      type,
      timestamp: Date.now(),
    };
    setLogs(prev => [newLog, ...prev]);
  };

  const deleteLog = (id: string) => {
    setLogs(prev => prev.filter(log => log.id !== id));
  };

  const todayKey = getTodayKey();
  const todayLogs = useMemo(() => {
    return logs.filter(log => new Date(log.timestamp).toISOString().split('T')[0] === todayKey);
  }, [logs, todayKey]);

  const todayTotal = todayLogs.reduce((acc, log) => acc + log.amount, 0);
  const progressPercentage = profile ? (todayTotal / profile.dailyGoal) * 100 : 0;
  const isGoalMetToday = progressPercentage >= 100;

  const streakStats = useMemo(() => {
    if (!profile) return { currentStreak: 0, bestStreak: 0 };
    return calculateStreaks(logs, profile.dailyGoal);
  }, [logs, profile]);

  const historyData = useMemo<DailySummary[]>(() => {
    if (!profile) return [];
    const map = new Map<string, number>();
    const last7Days = Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - i);
      return d.toISOString().split('T')[0];
    }).reverse();
    last7Days.forEach(date => map.set(date, 0));
    logs.forEach(log => {
      const dateKey = new Date(log.timestamp).toISOString().split('T')[0];
      if (map.has(dateKey)) map.set(dateKey, map.get(dateKey)! + log.amount);
    });
    return Array.from(map.entries()).map(([date, total]) => ({
      date,
      total,
      goal: profile.dailyGoal
    }));
  }, [logs, profile]);

  if (!profile) {
    return (
      <div className="min-h-screen bg-[#05070a] flex items-center justify-center p-6 relative overflow-hidden">
        <div className="absolute top-[-20%] right-[-10%] w-[600px] h-[600px] bg-blue-600/10 blur-[150px] rounded-full" />
        <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-indigo-600/10 blur-[150px] rounded-full" />
        <SetupForm onComplete={handleProfileComplete} />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#05070a] pb-44 text-slate-100 overflow-x-hidden relative selection:bg-blue-500/30">

      {/* Dynamic Background */}
      <div className="fixed inset-0 pointer-events-none z-0">
        <div className="absolute top-[-5%] right-[-5%] w-[60vw] h-[60vw] bg-blue-600/[0.03] blur-[120px] rounded-full" />
        <div className="absolute bottom-[10%] left-[-5%] w-[50vw] h-[50vw] bg-indigo-600/[0.03] blur-[120px] rounded-full" />
        <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/dark-matter.png')] opacity-[0.05]" />
      </div>

      <header className="relative z-50 bg-[#0a0c10]/80 backdrop-blur-3xl border-b border-white/5 px-8 py-6 flex items-center justify-between shadow-2xl">
        <div className="flex items-center gap-4 group">
          <div className="relative">
            <div className="absolute inset-0 bg-blue-500 blur-xl opacity-20 group-hover:opacity-40 transition-opacity" />
            <div className="relative bg-gradient-to-br from-blue-500/20 to-indigo-600/20 p-3 rounded-2xl border border-white/10">
              <Droplets className="w-6 h-6 text-blue-400" />
            </div>
          </div>
          <div>
            <h1 className="text-xl font-black tracking-tight text-white leading-none">AuraFlow</h1>
            <p className="text-[10px] font-bold text-blue-500/60 tracking-[0.25em] mt-1.5 uppercase">Premium Hydration</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
          <StreakBadge count={streakStats.currentStreak} />
          <button onClick={() => setProfile(null)} className="p-3 bg-white/[0.03] border border-white/10 rounded-2xl text-slate-400 hover:text-white hover:bg-white/10 transition-all active:scale-90">
            <Settings className="w-5 h-5" />
          </button>
        </div>
      </header>

      <main className="max-w-xl mx-auto px-6 py-8 space-y-12 relative z-10">
        {activeTab === 'today' && (
          <div className="space-y-12 animate-in fade-in slide-in-from-bottom-6 duration-1000">
            <CharacterStage percentage={progressPercentage} />

            <div className="flex flex-col items-center">
              <WaterWave percentage={progressPercentage} />

              <div className="mt-12 text-center group">
                <div className={`text-8xl font-black tracking-tighter transition-all duration-1000 ${isGoalMetToday ? 'text-blue-400 drop-shadow-[0_0_30px_rgba(59,130,246,0.3)]' : 'text-white'}`}>
                  {formatVolume(todayTotal)}
                </div>
                <div className="flex items-center justify-center gap-5 mt-4">
                  <div className="h-[1px] w-12 bg-gradient-to-r from-transparent to-white/10" />
                  <div className="text-slate-500 font-extrabold uppercase tracking-[0.4em] text-[10px]">
                    Quota: {formatVolume(profile.dailyGoal)}
                  </div>
                  <div className="h-[1px] w-12 bg-gradient-to-l from-transparent to-white/10" />
                </div>
              </div>
            </div>

            <AICoachCard profile={profile} currentIntake={todayTotal} />

            <section className="space-y-6">
              <div className="flex items-center gap-3">
                <div className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-pulse" />
                <h3 className="text-[11px] font-black tracking-[0.3em] uppercase text-slate-500">Intake Calibration</h3>
              </div>
              <div className="grid grid-cols-2 gap-4">
                {INTAKE_PRESETS.map((preset, idx) => (
                  <button 
                    key={idx} 
                    onClick={() => addLog(preset.amount)} 
                    className="relative group flex items-center justify-between p-7 bg-white/[0.02] border border-white/5 rounded-[2rem] hover:border-blue-500/40 hover:bg-white/[0.04] transition-all active:scale-95 shadow-lg overflow-hidden"
                  >
                    <div className="absolute top-0 right-0 p-3 opacity-0 group-hover:opacity-100 transition-opacity">
                      <ChevronRight size={14} className="text-blue-400" />
                    </div>
                    <div className="flex flex-col items-start gap-1 relative z-10">
                      <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">{preset.label}</span>
                      <span className="font-black text-2xl text-white tracking-tighter">{preset.amount}ml</span>
                    </div>
                    <div className="text-blue-400/30 group-hover:text-blue-400 group-hover:scale-110 transition-all duration-500">
                      {preset.icon}
                    </div>
                  </button>
                ))}
              </div>

              <div className="relative bg-[#0a0c10]/40 border border-white/5 rounded-[2.5rem] p-7 flex gap-7 overflow-x-auto scrollbar-hide shadow-inner backdrop-blur-md">
                {OTHER_DRINKS.map((drink, idx) => (
                  <button 
                    key={idx} 
                    onClick={() => addLog(Math.round(drink.amount * drink.hydratingFactor), drink.label)} 
                    className="flex-shrink-0 flex flex-col items-center gap-3 group"
                  >
                    <div className="w-16 h-16 rounded-[1.5rem] bg-white/[0.03] border border-white/5 flex items-center justify-center group-hover:bg-blue-600/10 group-hover:border-blue-500/30 group-hover:scale-105 transition-all duration-500 shadow-sm">
                      <div className="text-slate-500 group-hover:text-blue-400 transition-colors">
                        {drink.icon}
                      </div>
                    </div>
                    <span className="text-[9px] font-bold uppercase text-slate-500 tracking-widest group-hover:text-blue-400">{drink.label}</span>
                  </button>
                ))}
              </div>
            </section>

            <section className="space-y-6">
              <div className="flex items-center justify-between px-2">
                <h3 className="text-[11px] font-black tracking-[0.3em] uppercase text-slate-500">Activity Registry</h3>
                <div className="text-[9px] font-black text-blue-400 px-4 py-1.5 bg-blue-500/10 rounded-full border border-blue-500/20 uppercase tracking-widest">
                  {todayLogs.length} Records
