              </div>
              <div className="space-y-4">
                {todayLogs.length === 0 ? (
                  <div className="text-center py-24 bg-white/[0.01] rounded-[3rem] border border-white/5 text-slate-600 font-bold text-xs uppercase tracking-[0.2em] italic">
                    The registry is currently void.
                  </div>
                ) : (
                  todayLogs.map(log => (
                    <div key={log.id} className="group bg-white/[0.02] p-6 rounded-[2rem] flex items-center justify-between border border-white/5 hover:border-blue-500/10 hover:bg-white/[0.04] transition-all shadow-sm">
                      <div className="flex items-center gap-6">
                        <div className="bg-blue-500/5 p-4 rounded-2xl text-blue-400 border border-white/5">
                          <Droplet size={20} />
                        </div>
                        <div>
                          <div className="font-black text-2xl text-white tracking-tighter">+{log.amount}ml</div>
                          <div className="text-[10px] text-slate-500 uppercase font-bold tracking-[0.15em] mt-1">
                            {new Date(log.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} • {log.type}
                          </div>
                        </div>
                      </div>
                      <button onClick={() => deleteLog(log.id)} className="p-3 text-slate-700 hover:text-red-400 hover:bg-red-400/5 rounded-2xl transition-all">
                        <Trash2 size={20} />
                      </button>
                    </div>
                  ))
                )}
              </div>
            </section>
          </div>
        )}

        {activeTab === 'trends' && (
          <div className="space-y-12 animate-in fade-in slide-in-from-bottom-6 duration-1000">
            <HistoryChart data={historyData} />
            <div className="bg-[#0a0c10]/60 backdrop-blur-3xl rounded-[3.5rem] p-12 border border-white/5 flex flex-col items-center text-center shadow-2xl relative overflow-hidden group">
              <div className="absolute top-0 right-0 w-64 h-64 bg-blue-500/[0.03] blur-[100px] rounded-full group-hover:bg-blue-500/[0.05] transition-colors" />
              <StreakBadge count={streakStats.currentStreak} size="lg" />
              <div className="mt-12 grid grid-cols-2 w-full gap-10 border-t border-white/5 pt-12">
                <div className="space-y-2">
                  <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Ongoing Streak</div>
                  <div className="text-6xl font-black text-white tracking-tighter">{streakStats.currentStreak}<span className="text-xs font-bold text-slate-600 uppercase ml-3">Days</span></div>
                </div>
                <div className="border-l border-white/5 space-y-2">
                  <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Mean Flow</div>
                  <div className="text-6xl font-black text-blue-400 tracking-tighter">
                    {Math.round(historyData.reduce((acc, curr) => acc + curr.total, 0) / (historyData.length || 1))}<span className="text-xs font-bold text-slate-600 uppercase ml-2">ml</span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'aura' && <ImageEditor />}
      </main>

      {/* Persistent Premium Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 bg-[#0a0c10]/90 backdrop-blur-3xl border-t border-white/10 px-10 pt-8 pb-4 z-50 flex flex-col items-center shadow-[0_-10px_40px_rgba(0,0,0,0.5)]">
        <div className="w-full flex items-center justify-between mb-8">
          <NavButton active={activeTab === 'today'} icon={<Layout />} label="Dashboard" onClick={() => setActiveTab('today')} />
          <NavButton active={activeTab === 'aura'} icon={<Sparkles />} label="Vitality" onClick={() => setActiveTab('aura')} />
          <NavButton active={activeTab === 'trends'} icon={<History />} label="Analytics" onClick={() => setActiveTab('trends')} />
        </div>
        <div className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-600 select-none pb-2 opacity-50 hover:opacity-100 transition-opacity">
          developed by vicky
        </div>
      </nav>

      <style>{`
        .animate-in {
          animation: fadeIn 0.8s cubic-bezier(0.16, 1, 0.3, 1) forwards;
        }
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(15px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </div>
  );
};

