import React, { useEffect, useState, useRef } from 'react';

export default function WaterWave({ percentage }: { percentage: number }) {
  const clamped = Math.min(100, Math.max(0, percentage));
  const fillLevel = 100 - clamped;
  const isFull = clamped >= 100;
  const [ripples, setRipples] = useState<{ id: number }[]>([]);
  const [isSurging, setIsSurging] = useState(false);
  const prevRef = useRef(clamped);

  useEffect(() => {
    if (clamped > prevRef.current) {
      setIsSurging(true);
      setTimeout(() => setIsSurging(false), 800);
    }
    prevRef.current = clamped;
  }, [clamped]);

  useEffect(() => {
    const interval = setInterval(() => {
      setRipples(p => [...p.slice(-2), { id: Date.now() }]);
    }, 4000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="relative group">
      {/* Exterior Ambient Blur */}
      <div className={`absolute -inset-16 rounded-full opacity-[0.08] blur-[120px] transition-all duration-1000 ${isSurging ? 'scale-125 opacity-25 bg-blue-400' : 'bg-indigo-600'}`} />

      {/* High-Resolution Vessel */}
      <div className={`relative w-80 h-80 rounded-full border-[1.5px] border-white/10 bg-[#05070a] overflow-hidden shadow-[0_40px_80px_rgba(0,0,0,0.8)] transition-all duration-1000 ${isSurging ? 'scale-105 border-blue-500/30' : ''}`}>

        {/* Dynamic Liquid Layer */}
        <div className="absolute inset-0 transition-transform duration-[2500ms] cubic-bezier(0.16, 1, 0.3, 1)" style={{ transform: `translateY(${fillLevel}%)` }}>
          {/* Surface Interaction Line */}
          <div className={`absolute top-0 left-0 w-full z-20 transition-all ${isSurging ? 'h-10 bg-white/20 shadow-[0_0_60px_rgba(255,255,255,0.4)]' : 'h-[1.5px] bg-blue-400 shadow-[0_0_25px_#3b82f6]'}`}>
            <div className="w-full h-full bg-gradient-to-r from-transparent via-white/40 to-transparent animate-scan" />
          </div>

          {/* Gradient Fluid Core */}
          <div className={`w-full h-[210%] transition-colors duration-1000 relative overflow-hidden ${isSurging ? 'bg-blue-500' : 'bg-gradient-to-b from-blue-600 via-indigo-950 to-black'}`}>
             <div className="absolute inset-0 opacity-[0.06] bg-[url('https://www.transparenttextures.com/patterns/dark-matter.png')]" />
             <div className="absolute top-0 left-0 w-full h-32 bg-gradient-to-b from-white/10 to-transparent opacity-20" />
          </div>
        </div>

        {/* Biometric Ripples */}
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
          {ripples.map(r => (
            <div key={r.id} className="absolute border-[0.5px] border-white/10 rounded-full animate-ripple" 
              style={{ width: '10px', height: '10px' }} 
            />
          ))}
        </div>

        {/* Percentage Telemetry */}
        <div className="absolute inset-0 flex flex-col items-center justify-center z-30">
          <div className="relative group-hover:scale-110 transition-transform duration-700">
            <span className={`text-[6rem] font-black transition-colors duration-1000 tracking-tighter ${clamped > 50 ? 'text-white drop-shadow-[0_10px_20px_rgba(0,0,0,0.5)]' : 'text-blue-500'}`}>
              {Math.round(clamped)}
              <span className="text-2xl ml-1 font-extrabold opacity-40">%</span>
            </span>
          </div>
          <div className={`text-[10px] font-black uppercase tracking-[0.6em] mt-2 transition-all duration-700 ${clamped > 50 ? 'text-white/40' : 'text-slate-700'}`}>
            {isFull ? 'Target Achieved' : 'Saturation Index'}
          </div>
        </div>
      </div>
      <style>{`
        @keyframes ripple { 0% { transform: scale(0); opacity: 0.5; } 100% { transform: scale(70); opacity: 0; } }
        @keyframes scan { 0% { transform: translateX(-100%); } 100% { transform: translateX(100%); } }
        .animate-ripple { animation: ripple 10s cubic-bezier(0, 0, 0.2, 1) forwards; }
        .animate-scan { animation: scan 3s linear infinite; }
      `}</style>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Settings, 
  Trash2, 
  History, 
  Droplets,
  Waves,
  Sparkles,
  Droplet,
  Sword,
  Shield,
  Zap,
  Flame,
  Wind
} from 'lucide-react';
import { UserProfile, IntakeLog, DailySummary } from './types';
import { STORAGE_KEYS, INTAKE_PRESETS, OTHER_DRINKS } from './constants';
import { getTodayKey, formatVolume, calculateStreaks } from './utils/calculations';
import SetupForm from './components/SetupForm';
import WaterWave from './components/WaterWave';
import AICoachCard from './components/AICoachCard';
import HistoryChart from './components/HistoryChart';
import StreakBadge from './components/StreakBadge';
import ImageEditor from './components/ImageEditor';
import CharacterStage from './components/CharacterStage';

const App: React.FC = () => {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [logs, setLogs] = useState<IntakeLog[]>([]);
  const [activeTab, setActiveTab] = useState<'today' | 'trends' | 'aura'>('today');

  useEffect(() => {
    const savedProfile = localStorage.getItem(STORAGE_KEYS.USER_PROFILE);
    const savedLogs = localStorage.getItem(STORAGE_KEYS.INTAKE_LOGS);
    if (savedProfile) setProfile(JSON.parse(savedProfile));
    if (savedLogs) setLogs(JSON.parse(savedLogs));
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.INTAKE_LOGS, JSON.stringify(logs));
  }, [logs]);

  const handleProfileComplete = (newProfile: UserProfile) => {
    setProfile(newProfile);
    localStorage.setItem(STORAGE_KEYS.USER_PROFILE, JSON.stringify(newProfile));
  };

  const addLog = (amount: number, type: string = "Water") => {
    const newLog: IntakeLog = {
      id: Math.random().toString(36).substr(2, 9),
      amount,
      type,
      timestamp: Date.now(),
    };
    setLogs(prev => [newLog, ...prev]);
  };

  const deleteLog = (id: string) => {
    setLogs(prev => prev.filter(log => log.id !== id));
  };

  const todayKey = getTodayKey();
  const todayLogs = useMemo(() => {
    return logs.filter(log => new Date(log.timestamp).toISOString().split('T')[0] === todayKey);
  }, [logs, todayKey]);

  const todayTotal = todayLogs.reduce((acc, log) => acc + log.amount, 0);
  const progressPercentage = profile ? (todayTotal / profile.dailyGoal) * 100 : 0;
  const isGoalMetToday = progressPercentage >= 100;

  const streakStats = useMemo(() => {
    if (!profile) return { currentStreak: 0, bestStreak: 0 };
    return calculateStreaks(logs, profile.dailyGoal);
  }, [logs, profile]);

  const historyData = useMemo<DailySummary[]>(() => {
    if (!profile) return [];
    const map = new Map<string, number>();
    const last7Days = Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - i);
      return d.toISOString().split('T')[0];
    }).reverse();
    last7Days.forEach(date => map.set(date, 0));
    logs.forEach(log => {
      const dateKey = new Date(log.timestamp).toISOString().split('T')[0];
      if (map.has(dateKey)) map.set(dateKey, map.get(dateKey)! + log.amount);
    });
    return Array.from(map.entries()).map(([date, total]) => ({
      date,
      total,
      goal: profile.dailyGoal
    }));
  }, [logs, profile]);

  if (!profile) {
    return (
      <div className="min-h-screen bg-[#02040a] flex items-center justify-center p-4">
        <SetupForm onComplete={handleProfileComplete} />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#02040a] pb-40 text-slate-100 overflow-x-hidden relative selection:bg-cyan-500/30">

      {/* Background Cinematic Layers */}
      <div className="fixed inset-0 pointer-events-none z-0 overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-b from-[#02040a] via-[#0b1221] to-[#02040a] opacity-100" />
        <div className="absolute bottom-0 left-0 right-0 h-[60vh] bg-[url('https://www.transparenttextures.com/patterns/dark-matter.png')] opacity-20" />
        <div className="absolute inset-0 opacity-40 mix-blend-screen animate-fog-slow" 
          style={{ backgroundImage: 'radial-gradient(circle at 50% 50%, rgba(255,255,255,0.05) 0%, transparent 70%)' }} />

        <div className="absolute inset-0 z-10">
          {[...Array(20)].map((_, i) => (
            <div key={i} className="absolute bg-white/40 rounded-full blur-[1px] animate-float-particle" 
              style={{
                width: Math.random() * 4 + 2 + 'px',
                height: Math.random() * 4 + 2 + 'px',
                left: Math.random() * 100 + '%',
                top: Math.random() * 100 + '%',
                animationDelay: Math.random() * 5 + 's',
                animationDuration: Math.random() * 10 + 10 + 's'
              }} 
            />
          ))}
        </div>
        <div className="absolute top-[-10%] right-[-10%] w-[500px] h-[500px] bg-blue-500/10 blur-[120px] rounded-full" />
      </div>

      <header className="relative z-50 bg-black/40 backdrop-blur-xl border-b border-white/5 px-6 py-5 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="relative">
            <div className="absolute inset-0 bg-cyan-500 blur-lg opacity-40 animate-pulse" />
            <div className="relative bg-black border border-white/20 p-2.5 rounded-lg rotate-45 transform">
              <Sword className="w-5 h-5 text-cyan-400 -rotate-45" />
            </div>
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tighter text-white italic leading-none">KYOJIN</h1>
            <p className="text-[9px] font-black text-cyan-500 tracking-[0.4em] mt-1 uppercase">Hydration Slayer</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
          <StreakBadge count={streakStats.currentStreak} />
          <button onClick={() => setProfile(null)} className="p-2.5 bg-white/5 border border-white/10 rounded-xl text-slate-400 hover:text-white hover:border-cyan-500 transition-all">
            <Settings className="w-5 h-5" />
          </button>
        </div>
      </header>

      <main className="max-w-xl mx-auto px-6 py-8 space-y-12 relative z-10">
        {activeTab === 'today' && (
          <>
            <div className="flex flex-col items-center justify-center">
              <CharacterStage percentage={progressPercentage} />

              <div className="mt-4 flex flex-col items-center space-y-12 w-full">
                <WaterWave percentage={progressPercentage} />

                <div className="text-center group">
                  <div className="relative inline-block">
                    <div className="absolute -inset-4 bg-cyan-500/20 blur-2xl rounded-full opacity-0 group-hover:opacity-100 transition-opacity" />
                    <div className={`text-7xl font-black tracking-tighter italic transition-all duration-700 ${isGoalMetToday ? 'text-cyan-400 drop-shadow-[0_0_25px_rgba(34,211,238,0.6)]' : 'text-white'}`}>
                      {formatVolume(todayTotal)}
                    </div>
                  </div>
                  <div className="flex items-center justify-center gap-4 mt-4">
                    <div className="h-[1px] w-12 bg-gradient-to-r from-transparent to-white/20" />
                    <div className="text-slate-500 font-black uppercase tracking-[0.5em] text-[10px]">
                      THRESHOLD: {formatVolume(profile.dailyGoal)}
                    </div>
                    <div className="h-[1px] w-12 bg-gradient-to-l from-transparent to-white/20" />
                  </div>
                </div>
              </div>
            </div>

            <AICoachCard profile={profile} currentIntake={todayTotal} />

            <section className="space-y-6">
              <div className="flex items-center gap-3">
                <div className="w-8 h-[2px] bg-cyan-500 rounded-full" />
                <h3 className="text-lg font-black tracking-tighter uppercase italic text-white">Replenish Arts</h3>
              </div>
              <div className="grid grid-cols-2 gap-4">
                {INTAKE_PRESETS.map((preset, idx) => (
                  <button 
                    key={idx} 
                    onClick={() => addLog(preset.amount)} 
                    className="relative group flex items-center gap-4 p-5 bg-black/40 border border-white/10 rounded-2xl hover:border-cyan-500/50 hover:bg-black/60 transition-all active:scale-95 overflow-hidden"
                  >
                    <div className="absolute top-0 left-0 w-1 h-full bg-cyan-500 transform -translate-x-full group-hover:translate-x-0 transition-transform" />
                    <div className="bg-white/5 p-3 rounded-xl group-hover:bg-cyan-500 group-hover:text-black transition-all">
                      {preset.icon}
                    </div>
                    <div className="flex flex-col items-start">
                      <span className="font-black text-xl text-white italic">{preset.amount}ml</span>
                      <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">{preset.label}</span>
                    </div>
                  </button>
                ))}
              </div>

              <div className="relative">
                <div className="absolute inset-0 bg-white/5 blur-sm -m-1 rounded-[2.5rem]" />
                <div className="relative bg-black/40 border border-white/10 rounded-[2rem] p-6 flex gap-6 overflow-x-auto scrollbar-hide shadow-2xl">
                  {OTHER_DRINKS.map((drink, idx) => (
                    <button 
                      key={idx} 
                      onClick={() => addLog(Math.round(drink.amount * drink.hydratingFactor), drink.label)} 
                      className="flex-shrink-0 flex flex-col items-center gap-3 group"
                    >
                      <div className="w-16 h-16 rounded-2xl bg-white/5 border border-white/10 flex items-center justify-center group-hover:bg-cyan-500 group-hover:text-black group-hover:scale-110 group-active:scale-95 transition-all shadow-xl">
                        {drink.icon}
                      </div>
                      <span className="text-[9px] font-black uppercase text-slate-500 tracking-tighter group-hover:text-cyan-400">{drink.label}</span>
                    </button>
                  ))}
                </div>
              </div>
            </section>

            <section className="space-y-4">
              <div className="flex items-center justify-between px-2">
                <h3 className="text-lg font-black tracking-tighter uppercase italic text-white">Scroll of Deeds</h3>
                <div className="text-[10px] font-black bg-cyan-500/10 border border-cyan-500/30 text-cyan-400 px-4 py-1.5 rounded-full uppercase tracking-widest">
                  {todayLogs.length} Records
