              <div className="space-y-4">
                {todayLogs.length === 0 ? (
                  <div className="text-center py-20 bg-white/5 rounded-[2.5rem] border border-white/10 text-slate-600 font-black uppercase tracking-[0.3em] text-[10px] italic">
