                ) : (
                  todayLogs.map(log => (
                    <div key={log.id} className="group relative bg-black/40 p-5 rounded-2xl flex items-center justify-between border border-white/10 hover:border-cyan-500/30 transition-all">
                      <div className="flex items-center gap-5">
                        <div className="relative">
                          <div className="absolute inset-0 bg-cyan-500 blur-md opacity-20 group-hover:opacity-40" />
