                             <Droplet size={20} />
                          </div>
                        </div>
                        <div>
                          <div className="font-black text-2xl italic text-white leading-none">+{log.amount}ml</div>
                          <div className="text-[10px] text-slate-500 uppercase font-black tracking-widest flex items-center gap-2 mt-2">
                            {new Date(log.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} 
                            <span className="w-1 h-1 bg-white/20 rounded-full" /> 
                            {log.type}
