                        </div>
                      </div>
                      <button onClick={() => deleteLog(log.id)} className="p-3 text-white/20 hover:text-red-500 hover:bg-red-500/10 rounded-xl transition-all">
                        <Trash2 size={20} />
                      </button>
                    </div>
                  ))
                )}
              </div>
            </section>
          </>
        )}

        {activeTab === 'trends' && (
          <div className="space-y-10 animate-in fade-in slide-in-from-bottom-6 duration-700">
            <HistoryChart data={historyData} />
            <div className="relative group">
              <div className="absolute -inset-1 bg-gradient-to-r from-cyan-500 to-blue-600 rounded-[3rem] blur opacity-20 group-hover:opacity-40 transition-opacity" />
              <div className="relative bg-black/60 rounded-[3rem] p-12 border border-white/10 flex flex-col items-center text-center shadow-2xl backdrop-blur-xl">
                <StreakBadge count={streakStats.currentStreak} size="lg" />
                <div className="mt-12 grid grid-cols-2 w-full gap-10 border-t border-white/5 pt-10">
                  <div className="space-y-2">
