import { GoogleGenAI, Type } from "@google/genai";
import { UserProfile } from "../types";

const apiKey = process.env.API_KEY;

export const getHydrationAdvice = async (profile: UserProfile, currentIntake: number) => {
  const ai = new GoogleGenAI({ apiKey });
  const prompt = `As a professional health coach, provide a brief (max 2 sentences), encouraging hydration tip based on: Climate: ${profile.climate}, Exercise: ${profile.exerciseMinutesPerSession} min, Caffeine: ${profile.caffeineCups} cups, Progress: ${Math.round((currentIntake / profile.dailyGoal) * 100)}%. Keep it focused and professional.`;
  try {
    const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });
    return response.text;
  } catch (error) {
    return "Staying hydrated is essential for peak performance. Keep tracking your intake!";
  }
};

export const parseIntakeFromText = async (text: string): Promise<{ amount: number; type: string } | null> => {
  const ai = new GoogleGenAI({ apiKey });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Extract the drink type and amount in milliliters from this text: "${text}". If unit is not specified, estimate reasonably. Return JSON.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            amount: { type: Type.NUMBER, description: "Amount in milliliters" },
            type: { type: Type.STRING, description: "Type of drink (e.g., Water, Coffee)" }
          },
          required: ["amount", "type"]
        }
      }
    });

    return response.text ? JSON.parse(response.text) : null;
  } catch (error) {
    console.error("NLP Error", error);
    return null;
  }
};

export const parseIntakeFromImage = async (base64Image: string): Promise<{ amount: number; type: string } | null> => {
  const ai = new GoogleGenAI({ apiKey });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/jpeg' } },
          { text: "Analyze this image. Identify the beverage type and estimate the volume in milliliters. If unsure, provide a best guess. Return JSON." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            amount: { type: Type.NUMBER, description: "Estimated amount in milliliters" },
            type: { type: Type.STRING, description: "Type of drink" }
          },
          required: ["amount", "type"]
        }
      }
    });

    return response.text ? JSON.parse(response.text) : null;
  } catch (error) {
    console.error("Vision Error", error);
    return null;
  }
};

