        </div>
        <div className="flex items-center gap-3">
          <StreakBadge count={streakStats.currentStreak} />
          <button onClick={() => setProfile(null)} className="p-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-slate-400 hover:text-white transition-all">
            <Settings className="w-5 h-5" />
          </button>
        </div>
      </header>

      <main className="max-w-lg mx-auto px-6 py-6 space-y-8">
        {activeTab === 'today' && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <CharacterStage percentage={progressPercentage} />

            <div className="flex flex-col items-center">
              <WaterWave percentage={progressPercentage} />

              <div className="mt-8 text-center">
                <div className="text-6xl font-bold text-white tracking-tight">
                  {formatVolume(todayTotal)}
                </div>
                <p className="text-sm font-medium text-slate-500 mt-2 uppercase tracking-widest">
                  Daily Goal: {formatVolume(profile.dailyGoal)}
                </p>
              </div>
            </div>

            <AICoachCard profile={profile} currentIntake={todayTotal} />

            <section className="space-y-4">
              <h3 className="text-xs font-bold uppercase tracking-wider text-slate-500 pl-1">Quick Add</h3>
              <div className="grid grid-cols-2 gap-3">
                {INTAKE_PRESETS.map((preset, idx) => (
                  <button 
                    key={idx} 
                    onClick={() => addLog(preset.amount)} 
                    className="flex items-center gap-4 p-4 bg-slate-900 border border-slate-800 rounded-2xl hover:border-blue-500/50 hover:bg-slate-800 transition-all active:scale-95"
                  >
                    <div className="bg-slate-800 p-3 rounded-xl text-blue-400">
                      {preset.icon}
                    </div>
                    <div className="flex flex-col items-start">
                      <span className="font-bold text-xl text-white">{preset.amount}ml</span>
                      <span className="text-[10px] font-bold text-slate-500 uppercase">{preset.label}</span>
                    </div>
                  </button>
                ))}
              </div>
            </section>

            <section className="space-y-4">
               <div className="flex items-center justify-between px-1">
                <h3 className="text-xs font-bold uppercase tracking-wider text-slate-500">History</h3>
                <span className="text-[10px] font-bold bg-slate-800 text-slate-400 px-3 py-1 rounded-full">
                  {todayLogs.length} Entries
