                ) : (
                  todayLogs.map(log => (
                    <div key={log.id} className="bg-slate-900 p-4 rounded-2xl flex items-center justify-between border border-slate-800">
                      <div>
                        <div className="font-bold text-lg text-white">+{log.amount}ml</div>
                        <div className="text-xs text-slate-500 font-medium">
                          {new Date(log.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} • {log.type}
