                <div className="space-y-1">
                  <div className="text-xs font-bold text-slate-500 uppercase tracking-wider">Current Streak</div>
                  <div className="text-4xl font-bold text-white">{streakStats.currentStreak} <span className="text-sm text-slate-500">days</span></div>
                </div>
                <div className="border-l border-slate-800 space-y-1">
                  <div className="text-xs font-bold text-slate-500 uppercase tracking-wider">Daily Avg</div>
                  <div className="text-4xl font-bold text-blue-400">
                    {Math.round(historyData.reduce((acc, curr) => acc + curr.total, 0) / (historyData.length || 1))}
                    <span className="text-sm text-slate-500 ml-1">ml</span>
                  </div>
                </div>
              </div>
            </div>
