import React, { useState, useRef, useEffect } from 'react';
import { Camera, Mic, Send, Loader2, Image as ImageIcon, CheckCircle, Search, Keyboard } from 'lucide-react';
import { parseIntakeFromImage, parseIntakeFromText } from '../services/geminiService';

interface SmartLoggerProps {
  onLog: (amount: number, type: string) => void;
}

export default function SmartLogger({ onLog }: SmartLoggerProps) {
  const [mode, setMode] = useState<'text' | 'camera'>('text');
  const [inputText, setInputText] = useState('');
  const [image, setImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  // Speech Recognition Setup
  useEffect(() => {
    if (!('webkitSpeechRecognition' in window)) return;
    const recognition = new (window as any).webkitSpeechRecognition();
    recognition.continuous = false;
    recognition.interimResults = false;
    recognition.lang = 'en-US';

    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setInputText(transcript);
      setIsListening(false);
      handleAnalyzeText(transcript);
    };

    recognition.onerror = () => setIsListening(false);
    recognition.onend = () => setIsListening(false);

    if (isListening) recognition.start();
    else recognition.stop();

    return () => recognition.abort();
  }, [isListening]);

  const handleAnalyzeText = async (text: string) => {
    if (!text.trim()) return;
    setIsProcessing(true);
    const result = await parseIntakeFromText(text);
    setIsProcessing(false);
    if (result) onLog(result.amount, result.type);
    else alert("Could not understand the intake. Please try again.");
  };

  const handleAnalyzeImage = async () => {
    if (!image) return;
    setIsProcessing(true);
    const result = await parseIntakeFromImage(image);
    setIsProcessing(false);
    if (result) onLog(result.amount, result.type);
    else alert("Could not identify the drink. Please try again.");
  };

  return (
    <div className="bg-slate-900 rounded-3xl p-6 border border-slate-800 shadow-xl space-y-6">

      <div className="flex p-1 bg-slate-800 rounded-2xl">
        <button 
          onClick={() => setMode('text')} 
          className={`flex-1 py-3 rounded-xl text-sm font-bold transition-all flex items-center justify-center gap-2 ${mode === 'text' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
        >
          <Keyboard size={18} /> Text & Voice
        </button>
        <button 
          onClick={() => setMode('camera')} 
          className={`flex-1 py-3 rounded-xl text-sm font-bold transition-all flex items-center justify-center gap-2 ${mode === 'camera' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
        >
          <Camera size={18} /> Vision Scan
        </button>
      </div>

      {mode === 'text' ? (
        <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">
          <div className="text-center space-y-2 py-4">
             <h3 className="text-lg font-bold text-white">Natural Language Log</h3>
             <p className="text-slate-400 text-sm">"I just had a large coffee" or "Drank 500ml water"</p>
          </div>

          <div className="relative">
            <textarea
              className="w-full bg-slate-950 border border-slate-800 rounded-2xl p-4 text-white placeholder-slate-600 focus:ring-2 focus:ring-blue-500 outline-none resize-none h-32"
              placeholder="Type or speak what you drank..."
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
            />
            <button 
              onClick={() => setIsListening(!isListening)}
              className={`absolute bottom-3 right-3 p-3 rounded-xl transition-all ${isListening ? 'bg-red-500 animate-pulse text-white' : 'bg-slate-800 text-slate-400 hover:text-white'}`}
            >
              <Mic size={20} />
            </button>
          </div>

          <button 
            onClick={() => handleAnalyzeText(inputText)}
            disabled={!inputText || isProcessing}
            className="w-full bg-blue-600 hover:bg-blue-500 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold py-4 rounded-2xl flex items-center justify-center gap-2 transition-all"
          >
            {isProcessing ? <Loader2 className="animate-spin" /> : <Search size={20} />}
            {isProcessing ? 'Analyzing...' : 'Analyze Intake'}
          </button>
        </div>
      ) : (
        <div className="space-y-6 animate-in fade-in slide-in-from-left-4 duration-300">
          <div className="text-center space-y-2">
             <h3 className="text-lg font-bold text-white">AI Vision Scanner</h3>
             <p className="text-slate-400 text-sm">Take a photo of your drink to estimate volume</p>
          </div>

          <div className="relative aspect-square bg-slate-950 border-2 border-dashed border-slate-800 rounded-3xl flex items-center justify-center overflow-hidden hover:border-blue-500/50 transition-colors">
            {image ? (
              <img src={image} className="w-full h-full object-cover" alt="Drink preview" />
            ) : (
              <button 
                onClick={() => inputRef.current?.click()} 
                className="flex flex-col items-center gap-3 text-slate-500 hover:text-blue-400 transition-colors"
              >
                <div className="p-4 bg-slate-900 rounded-full">
                    <ImageIcon size={32} />
                </div>
                <span className="font-semibold text-sm">Upload Photo</span>
              </button>
            )}

            {image && (
              <button 
                onClick={() => setImage(null)} 
                className="absolute top-2 right-2 p-2 bg-black/50 text-white rounded-full hover:bg-red-500 transition-colors"
              >
                <Loader2 className={isProcessing ? "animate-spin" : "hidden"} />
                {!isProcessing && "✕"}
              </button>
            )}
          </div>

          <input 
            type="file" 
            ref={inputRef} 
            accept="image/*" 
            hidden 
            onChange={e => {
              const file = e.target.files?.[0];
              if (file) { 
                const r = new FileReader(); 
                r.onload = () => setImage(r.result as string); 
                r.readAsDataURL(file); 
              }
            }} 
          />

          <button 
            onClick={handleAnalyzeImage}
            disabled={!image || isProcessing}
            className="w-full bg-blue-600 hover:bg-blue-500 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold py-4 rounded-2xl flex items-center justify-center gap-2 transition-all"
          >
            {isProcessing ? <Loader2 className="animate-spin" /> : <CheckCircle size={20} />}
            {isProcessing ? 'Processing Image...' : 'Confirm & Log'}
          </button>
        </div>
      )}
    </div>
  );
}

import React, { useState } from 'react';
import { UserProfile, Gender, ActivityLevel, Climate, WeightUnit } from '../types';
import { calculateHydrationGoal } from '../utils/calculations';
import { User, Activity, Ruler, Weight } from 'lucide-react';

interface SetupFormProps {
  onComplete: (profile: UserProfile) => void;
  initialProfile?: UserProfile | null;
}

const SetupForm: React.FC<SetupFormProps> = ({ onComplete, initialProfile }) => {
  const [formData, setFormData] = useState<Omit<UserProfile, 'dailyGoal'>>({
    name: initialProfile?.name || '',
    age: initialProfile?.age || 25,
    weight: initialProfile?.weight || 70,
    weightUnit: initialProfile?.weightUnit || WeightUnit.KG,
    height: initialProfile?.height || 170,
    gender: initialProfile?.gender || Gender.MALE,
    activityLevel: initialProfile?.activityLevel || ActivityLevel.LIGHT,
    exerciseMinutesPerSession: initialProfile?.exerciseMinutesPerSession || 45,
    exerciseDaysPerWeek: initialProfile?.exerciseDaysPerWeek || 3,
    climate: initialProfile?.climate || Climate.MODERATE,
    caffeineCups: initialProfile?.caffeineCups || 1,
    hasMedicalCondition: initialProfile?.hasMedicalCondition || false,
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const dailyGoal = calculateHydrationGoal(formData);
    onComplete({ ...formData, dailyGoal });
  };

  const updateField = (field: keyof typeof formData, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  return (
    <div className="max-w-xl w-full mx-auto bg-slate-900 border border-slate-800 rounded-3xl p-8 shadow-2xl">
      <div className="text-center mb-10">
        <h2 className="text-3xl font-bold text-white mb-2">Welcome to HydroSmart</h2>
        <p className="text-slate-400 text-sm">Let's calculate your optimal hydration plan.</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-8">
        <div className="space-y-4">
          <label className="text-xs font-bold uppercase text-slate-500 tracking-wider">Basic Info</label>
          <div className="grid grid-cols-1 gap-4">
            <input
              type="text"
              required
              placeholder="Your Name"
              className="w-full px-5 py-4 bg-slate-950 border border-slate-800 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none text-white font-medium"
              value={formData.name}
              onChange={(e) => updateField('name', e.target.value)}
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <input
              type="number"
              placeholder="Age"
              className="w-full px-5 py-4 bg-slate-950 border border-slate-800 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none text-white font-medium"
              value={formData.age}
              onChange={(e) => updateField('age', parseInt(e.target.value))}
            />
            <select
              className="w-full px-5 py-4 bg-slate-950 border border-slate-800 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none text-white font-medium appearance-none"
              value={formData.gender}
              onChange={(e) => updateField('gender', e.target.value as Gender)}
            >
              <option value={Gender.MALE}>Male</option>
              <option value={Gender.FEMALE}>Female</option>
              <option value={Gender.OTHER}>Other</option>
            </select>
          </div>
        </div>

        <button
          type="submit"
          className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-4 rounded-xl shadow-lg transition-all active:scale-95"
        >
          Create Profile
        </button>
      </form>
    </div>
  );
};

