import React from 'react';
import { 
  ComposedChart, 
  Bar, 
  XAxis, 
  YAxis, 
  Tooltip, 
  ResponsiveContainer, 
  Cell
} from 'recharts';
import { DailySummary } from '../types';

interface HistoryChartProps {
  data: DailySummary[];
}

const HistoryChart: React.FC<HistoryChartProps> = ({ data }) => {
  const maxVal = Math.max(...data.map(d => Math.max(d.total, d.goal)), 1000);
  const processedData = data.map((item) => ({
    ...item,
    displayDate: new Date(item.date).toLocaleDateString(undefined, { weekday: 'short' }),
    isGoalMet: item.total >= item.goal
  }));

  return (
    <div className="bg-slate-900 rounded-3xl p-6 border border-slate-800 h-72">
      <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-6">Weekly Overview</h3>
      <ResponsiveContainer width="100%" height="100%">
        <ComposedChart data={processedData}>
          <XAxis 
            dataKey="displayDate" 
            axisLine={false} 
            tickLine={false} 
            tick={{ fill: '#64748b', fontSize: 11, fontWeight: 600 }} 
            dy={10}
          />
          <YAxis hide domain={[0, maxVal * 1.1]} />
          <Tooltip 
            cursor={{ fill: 'rgba(255, 255, 255, 0.05)' }}
            content={({ active, payload }) => {
              if (active && payload && payload.length) {
                const item = payload[0].payload;
                return (
                  <div className="bg-slate-800 text-white p-3 rounded-xl text-xs shadow-xl border border-slate-700">
                    <p className="font-bold mb-1 text-slate-400">{item.displayDate}</p>
                    <p className="font-bold">{item.total}ml / {item.goal}ml</p>
                  </div>
                );
              }
              return null;
            }}
          />
          <Bar dataKey="total" radius={[6, 6, 6, 6]} barSize={20}>
            {processedData.map((entry, index) => (
              <Cell 
                key={`cell-${index}`} 
                fill={entry.total >= entry.goal ? '#3b82f6' : '#334155'} 
              />
            ))}
          </Bar>
        </ComposedChart>
      </ResponsiveContainer>
    </div>
  );
};

export default HistoryChart;

import React from 'react';

export default function WaterWave({ percentage }: { percentage: number }) {
  const clamped = Math.min(100, Math.max(0, percentage));
  const fillLevel = 100 - clamped;

  return (
    <div className="relative w-64 h-64">
      <div className="absolute inset-0 bg-blue-500/5 rounded-full blur-3xl" />
      <div className="relative w-full h-full rounded-full border-4 border-slate-800 bg-slate-900 overflow-hidden shadow-2xl">
        <div className="absolute inset-0 transition-transform duration-1000 ease-in-out" style={{ transform: `translateY(${fillLevel}%)` }}>
           <div className="absolute top-0 left-0 right-0 h-4 bg-white/20 blur-md" />
           <div className="w-full h-[200%] bg-blue-600" />
        </div>
        <div className="absolute inset-0 flex flex-col items-center justify-center z-10">
          <span className={`text-5xl font-bold transition-colors duration-500 ${clamped > 55 ? 'text-white' : 'text-slate-200'}`}>
            {Math.round(clamped)}%
          </span>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { Camera, Mic, Send, Loader2, Image as ImageIcon, CheckCircle, Search, Keyboard, RefreshCw, XCircle } from 'lucide-react';
import { parseIntakeFromImage, parseIntakeFromText } from '../services/geminiService';

interface SmartLoggerProps {
  onLog: (amount: number, type: string) => void;
}

export default function SmartLogger({ onLog }: SmartLoggerProps) {
  const [mode, setMode] = useState<'text' | 'camera'>('text');
  const [inputText, setInputText] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [cameraActive, setCameraActive] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  // Speech Recognition Setup
  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return;

    const recognition = new SpeechRecognition();
    recognition.continuous = false;
    recognition.interimResults = true;
    recognition.lang = 'en-US';

    recognition.onresult = (event: any) => {
      const transcript = Array.from(event.results)
        .map((result: any) => result[0].transcript)
        .join('');
      setInputText(transcript);
    };

    recognition.onend = () => {
      setIsListening(false);
      if (inputText.trim()) {
        handleAnalyzeText(inputText);
      }
    };

    if (isListening) {
      recognition.start();
    } else {
      recognition.stop();
    }

    return () => recognition.abort();
  }, [isListening]);

  // Camera Management
  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' }, 
        audio: false 
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        streamRef.current = stream;
        setCameraActive(true);
      }
    } catch (err) {
      alert("Camera access denied. Please check permissions.");
    }
  };

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setCameraActive(false);
  };

  useEffect(() => {
    if (mode === 'camera') {
      startCamera();
    } else {
      stopCamera();
    }
    return () => stopCamera();
  }, [mode]);

  const handleAnalyzeText = async (text: string) => {
    if (!text.trim()) return;
    setIsProcessing(true);
    try {
      const result = await parseIntakeFromText(text);
      if (result) {
        onLog(result.amount, result.type);
      } else {
        alert("Could not extract details. Try: 'Drank 300ml water'");
      }
    } finally {
      setIsProcessing(false);
      setInputText('');
    }
  };

  const handleCaptureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current) return;

    setIsProcessing(true);
    const context = canvasRef.current.getContext('2d');
    if (context) {
      canvasRef.current.width = videoRef.current.videoWidth;
      canvasRef.current.height = videoRef.current.videoHeight;
      context.drawImage(videoRef.current, 0, 0);
      const base64Image = canvasRef.current.toDataURL('image/jpeg');

      const result = await parseIntakeFromImage(base64Image);
      if (result) {
        onLog(result.amount, result.type);
      } else {
        alert("AI could not identify the drink. Please ensure it's visible.");
      }
    }
    setIsProcessing(false);
  };

  return (
    <div className="bg-slate-900 rounded-[2rem] p-6 border border-slate-800 shadow-2xl space-y-6">

      {/* Tab Switcher */}
      <div className="flex p-1 bg-slate-800/50 rounded-2xl">
        <button 
          onClick={() => setMode('text')} 
          className={`flex-1 py-3 rounded-xl text-xs font-bold transition-all flex items-center justify-center gap-2 ${mode === 'text' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
        >
          <Keyboard size={16} /> NLP & VOICE
        </button>
        <button 
          onClick={() => setMode('camera')} 
          className={`flex-1 py-3 rounded-xl text-xs font-bold transition-all flex items-center justify-center gap-2 ${mode === 'camera' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
        >
          <Camera size={16} /> COMPUTER VISION
        </button>
      </div>

      {mode === 'text' ? (
        <div className="space-y-4 animate-in fade-in zoom-in-95 duration-300">
          <div className="text-center space-y-1 py-2">
             <h3 className="text-lg font-bold text-white">NLP Intake Log</h3>
             <p className="text-slate-500 text-xs">Speak naturally or type what you drank</p>
          </div>

          <div className="relative group">
            <textarea
              className="w-full bg-slate-950 border border-slate-800 rounded-2xl p-5 text-white placeholder-slate-700 focus:ring-2 focus:ring-blue-500 outline-none resize-none h-40 transition-all"
              placeholder="e.g. 'Just finished a small cup of green tea' or '500ml of water'..."
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
            />
            <div className="absolute bottom-4 right-4 flex items-center gap-2">
              {inputText && (
                <button 
                  onClick={() => setInputText('')}
                  className="p-2 text-slate-600 hover:text-slate-400"
                >
                  <XCircle size={20} />
                </button>
              )}
              <button 
                onClick={() => setIsListening(!isListening)}
                className={`p-4 rounded-full transition-all ${isListening ? 'bg-red-500 animate-pulse text-white shadow-[0_0_20px_rgba(239,68,68,0.4)]' : 'bg-slate-800 text-slate-400 hover:text-white'}`}
              >
                <Mic size={24} />
              </button>
            </div>
          </div>

          <button 
            onClick={() => handleAnalyzeText(inputText)}
            disabled={!inputText || isProcessing}
            className="w-full bg-blue-600 hover:bg-blue-500 disabled:opacity-30 disabled:cursor-not-allowed text-white font-bold py-4 rounded-2xl flex items-center justify-center gap-2 transition-all shadow-lg"
          >
            {isProcessing ? <Loader2 className="animate-spin" size={20} /> : <Search size={20} />}
            {isProcessing ? 'Processing Language...' : 'Log Intake'}
          </button>
        </div>
      ) : (
        <div className="space-y-6 animate-in fade-in zoom-in-95 duration-300">
          <div className="text-center space-y-1">
             <h3 className="text-lg font-bold text-white">Computer Vision Scan</h3>
             <p className="text-slate-500 text-xs">Point at your drink to estimate volume</p>
          </div>

          <div className="relative aspect-square bg-slate-950 rounded-3xl overflow-hidden border border-slate-800 shadow-inner group">
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              className={`w-full h-full object-cover transition-opacity duration-500 ${cameraActive ? 'opacity-100' : 'opacity-0'}`} 
            />
            <canvas ref={canvasRef} className="hidden" />

            {/* Visual Guides */}
            <div className="absolute inset-0 border-[40px] border-slate-950/40 pointer-events-none" />
            <div className="absolute inset-[40px] border-2 border-dashed border-white/20 rounded-2xl pointer-events-none group-hover:border-blue-500/50 transition-colors" />

            {!cameraActive && (
              <div className="absolute inset-0 flex items-center justify-center">
                <Loader2 className="animate-spin text-blue-500" size={32} />
              </div>
            )}

            {isProcessing && (
              <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm flex flex-col items-center justify-center gap-3">
                <Loader2 className="animate-spin text-blue-500" size={40} />
                <span className="text-xs font-bold text-blue-400 uppercase tracking-widest animate-pulse">Analyzing Frame...</span>
              </div>
            )}
          </div>

          <div className="flex gap-3">
            <button 
              onClick={handleCaptureAndAnalyze}
              disabled={isProcessing || !cameraActive}
              className="flex-[2] bg-blue-600 hover:bg-blue-500 disabled:opacity-30 text-white font-bold py-4 rounded-2xl flex items-center justify-center gap-2 shadow-lg transition-all"
            >
              <Camera size={20} /> Scan Drink
            </button>
            <button 
              onClick={startCamera}
              className="flex-1 bg-slate-800 text-slate-300 py-4 rounded-2xl flex items-center justify-center hover:bg-slate-700 transition-all"
            >
              <RefreshCw size={20} />
            </button>
          </div>
        </div>
      )}

      <div className="pt-2 text-center">
        <p className="text-[10px] font-bold text-slate-700 uppercase tracking-[0.2em]">
          Powered by Gemini Vision & NLP
        </p>
      </div>
    </div>
  );
}

import { GoogleGenAI, Type } from "@google/genai";
import { UserProfile } from "../types";

const apiKey = process.env.API_KEY;

export const getHydrationAdvice = async (profile: UserProfile, currentIntake: number) => {
  const ai = new GoogleGenAI({ apiKey });
  const prompt = `As a professional health coach, provide a brief (max 2 sentences), encouraging hydration tip based on: Climate: ${profile.climate}, Exercise: ${profile.exerciseMinutesPerSession} min, Caffeine: ${profile.caffeineCups} cups, Progress: ${Math.round((currentIntake / profile.dailyGoal) * 100)}%. Keep it focused, professional, and do not use greetings.`;
  try {
    const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });
    return response.text;
  } catch (error) {
    return "Staying hydrated is essential for peak performance. Keep tracking your intake!";
  }
};

export const parseIntakeFromText = async (text: string): Promise<{ amount: number; type: string } | null> => {
  const ai = new GoogleGenAI({ apiKey });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a hydration assistant. Extract the drink type and total volume in milliliters from this user input: "${text}". 
      Handle conversational phrases like 'just finished half a bottle' (estimate bottle as 500ml). 
      If no unit is given, assume milliliters based on context. 
      Return JSON only.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            amount: { type: Type.NUMBER, description: "Total volume in milliliters" },
            type: { type: Type.STRING, description: "The specific beverage name" }
          },
          required: ["amount", "type"]
        }
      }
    });

    return response.text ? JSON.parse(response.text) : null;
  } catch (error) {
    console.error("NLP Error", error);
    return null;
  }
};

export const parseIntakeFromImage = async (base64Image: string): Promise<{ amount: number; type: string } | null> => {
  const ai = new GoogleGenAI({ apiKey });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/jpeg' } },
          { text: "Analyze the beverage in this image. Estimate the volume in milliliters based on the container size and liquid level. Identify the drink type. Return JSON only." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            amount: { type: Type.NUMBER, description: "Estimated volume in milliliters" },
            type: { type: Type.STRING, description: "Identified drink type" }
          },
          required: ["amount", "type"]
        }
      }
    });

    return response.text ? JSON.parse(response.text) : null;
  } catch (error) {
    console.error("Vision Error", error);
    return null;
  }
};
